/* eslint-disable react-hooks/set-state-in-effect */
import {
  FormEvent,
  useCallback,
  useEffect,
  useLayoutEffect,
  useMemo,
  useReducer,
  useRef,
  useState,
} from "react";
import type { MouseEvent } from "react";
import type { CSSProperties } from "react";

import styles from "./GrayDashboardCalendar.module.css";
import {
  CalendarEntryType,
  CalendarEvent,
  CalendarInfo,
  CalendarEventDisplayHint,
} from "./types";
import { ArrowRight, Calendar, ChevronDown, ChevronLeft, ChevronRight, Plus, X } from "lucide-react";
import { useI18n } from "@/contexts/I18nContext";
import { MiniMonth } from "./MiniMonth";

export type EventComposerPayload = {
  id?: string;
  title: string;
  start: Date;
  end: Date;
  color: string;
  entryType: CalendarEntryType;
  calendarId: string;
  description?: string;
  displayHint?: CalendarEventDisplayHint;
  reminderMinutesBefore?: number | null;
};

type AnchorRect = {
  top: number;
  left: number;
  width: number;
  height: number;
};

type EventComposerProps = {
  isOpen: boolean;
  referenceDate: Date;
  activeEvent?: CalendarEvent | null;
  initialRange?: { start: Date; end: Date } | null;
  calendars: CalendarInfo[];
  onRequestClose: () => void;
  onSubmit: (payload: EventComposerPayload) => void;
  onDelete?: (eventId: string) => void;
  anchorRect?: AnchorRect | null;
  onStateChange?: (state: ComposerState) => void;
};

export type ComposerState = {
  title: string;
  startTime: string;
  endTime: string;
  color: string;
  entryType: CalendarEntryType;
  calendarId: string;
  details: string;
  reminderMinutesBefore: number | null;
};

type ComposerAction =
  | { type: "reset"; payload: ComposerState }
  | { type: "update"; payload: Partial<ComposerState> };

const QUICK_COLOR_SWATCHES = [
  "#2F6B4F",
  "#3D6F73",
  "#B77A2B",
  "#C45A3C",
  "#7A5A3A",
  "#7A6A55",
  "#BEB5A7",
  "#8A7F73",
] as const;

const clamp = (value: number, min: number, max: number) => Math.min(max, Math.max(min, value));

const rgbToHex = (red: number, green: number, blue: number) =>
  `#${[red, green, blue]
    .map((channel) => clamp(Math.round(channel), 0, 255).toString(16).padStart(2, "0"))
    .join("")}`.toUpperCase();

const hexToRgb = (hex: string) => {
  const normalized = hex.trim().replace(/^#/, "");
  if (!/^[0-9a-fA-F]{6}$/.test(normalized)) return null;
  const red = Number.parseInt(normalized.slice(0, 2), 16);
  const green = Number.parseInt(normalized.slice(2, 4), 16);
  const blue = Number.parseInt(normalized.slice(4, 6), 16);
  return { red, green, blue };
};

const normalizeHex = (raw: string) => {
  const trimmed = raw.trim();
  if (trimmed.length === 0) return null;
  const withHash = trimmed.startsWith("#") ? trimmed : `#${trimmed}`;
  const expanded =
    withHash.length === 4
      ? `#${withHash[1]}${withHash[1]}${withHash[2]}${withHash[2]}${withHash[3]}${withHash[3]}`
      : withHash;
  if (!/^#[0-9a-fA-F]{6}$/.test(expanded)) return null;
  return expanded.toUpperCase();
};

const hslToHex = (hue: number, saturation: number, lightness: number) => {
  const normalizedHue = ((hue % 360) + 360) % 360;
  const normalizedSaturation = clamp(saturation, 0, 100) / 100;
  const normalizedLightness = clamp(lightness, 0, 100) / 100;

  const chroma = (1 - Math.abs(2 * normalizedLightness - 1)) * normalizedSaturation;
  const huePrime = normalizedHue / 60;
  const secondComponent = chroma * (1 - Math.abs((huePrime % 2) - 1));
  const match = normalizedLightness - chroma / 2;

  const channelVariants: Array<[number, number, number]> = [
    [chroma, secondComponent, 0],
    [secondComponent, chroma, 0],
    [0, chroma, secondComponent],
    [0, secondComponent, chroma],
    [secondComponent, 0, chroma],
    [chroma, 0, secondComponent],
  ];

  const [redVariant, greenVariant, blueVariant] =
    channelVariants[Math.floor(clamp(huePrime, 0, 5.999))] ?? channelVariants[0];

  return rgbToHex(
    (redVariant + match) * 255,
    (greenVariant + match) * 255,
    (blueVariant + match) * 255
  );
};

const buildHslPalette = (options: {
  hues: number[];
  saturations: number[];
  lightnesses: number[];
}) => {
  const colors: string[] = [];
  for (const lightness of options.lightnesses) {
    for (const saturation of options.saturations) {
      for (const hue of options.hues) {
        colors.push(hslToHex(hue, saturation, lightness));
      }
    }
  }
  return Array.from(new Set(colors));
};

const EARTHY_PALETTE = buildHslPalette({
  hues: [18, 28, 40, 52, 75, 98, 130, 160, 190, 210, 240, 285, 320],
  saturations: [28, 38],
  lightnesses: [34, 44],
});

const PASTEL_PALETTE = buildHslPalette({
  hues: [16, 28, 40, 52, 75, 98, 130, 160, 190, 210, 240, 285, 320],
  saturations: [32, 44],
  lightnesses: [72, 80],
});

const NEUTRAL_PALETTE = [
  "#F3F0EA",
  "#E6DED3",
  "#D5CCBF",
  "#C2B8AA",
  "#A79D8F",
  "#8C8275",
  "#6F665B",
  "#574F46",
] as const;

// Default colors  by entry type
// Default colors  by entry type
const DEFAULT_COLORS: Record<CalendarEntryType, string> = {
  event: "#3D6F73",
  task: "#B77A2B",
  plan: "#5E7E91",
  habit: "#5E9182",
};

const DEFAULT_STATE: ComposerState = {
  title: "",
  startTime: "09:00",
  endTime: "10:00",
  color: DEFAULT_COLORS.event,
  entryType: "event",
  calendarId: "default",
  details: "",
  reminderMinutesBefore: null,
};

export const DEFAULT_EVENT_DURATION_MINUTES = 60;

const VISIBLE_ENTRY_TYPES: CalendarEntryType[] = ["plan", "habit", "event"];
const ENTRY_TYPE_LABELS: Record<CalendarEntryType, string> = {
  event: "Event",
  task: "Task",
  plan: "Plans",
  habit: "Habits",
};

const composerReducer = (state: ComposerState, action: ComposerAction): ComposerState => {
  switch (action.type) {
    case "reset":
      return action.payload;
    case "update":
      return { ...state, ...action.payload };
    default:
      return state;
  }
};

const formatTimeInput = (date: Date) =>
  date
    .toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    })
    .padStart(5, "0");

const resolveStateFromEvent = (
  event: CalendarEvent,
  fallbackCalendarId: string
): ComposerState => ({
  title: event.title,
  startTime: formatTimeInput(event.start),
  endTime: formatTimeInput(event.end),
  color: event.color,
  entryType: event.entryType,
  calendarId: event.calendarId ?? fallbackCalendarId,
  details: event.description ?? "",
  reminderMinutesBefore:
    typeof event.reminderMinutesBefore === "number" ? event.reminderMinutesBefore : null,
});

const combineDateWithTime = (date: Date, timeValue: string) => {
  const [hours, minutes] = timeValue.split(":").map((value) => Number.parseInt(value, 10));
  const result = new Date(date);
  result.setHours(Number.isFinite(hours) ? hours : 0, Number.isFinite(minutes) ? minutes : 0, 0, 0);
  return result;
};

const startOfDay = (value: Date) => {
  const result = new Date(value);
  result.setHours(0, 0, 0, 0);
  return result;
};

const startOfMonth = (value: Date) => {
  const result = startOfDay(value);
  result.setDate(1);
  return result;
};

const isPointerEventInside = (
  event: globalThis.PointerEvent,
  element: HTMLElement | null
) => {
  if (!element) return false;
  const target = event.target as Node | null;
  if (!target) return false;
  if (typeof event.composedPath === "function") {
    return event.composedPath().includes(element);
  }
  return element.contains(target);
};

export function EventComposer({
  isOpen,
  referenceDate,
  activeEvent,
  initialRange = null,
  calendars,
  onRequestClose,
  onSubmit,
  onStateChange,
  onDelete,
  anchorRect = null,
}: EventComposerProps) {
  const { t } = useI18n();
  const calendarFallbackId = useMemo(
    () => calendars[0]?.id ?? "default",
    [calendars]
  );

  const [state, dispatch] = useReducer(composerReducer, {
    ...DEFAULT_STATE,
    title: "",
    calendarId: calendarFallbackId,
  });
  const cardRef = useRef<HTMLDivElement | null>(null);
  const formRef = useRef<HTMLFormElement | null>(null);
  const colorPickerRef = useRef<HTMLDivElement | null>(null);
  const colorPickerTriggerRef = useRef<HTMLButtonElement | null>(null);
  const colorPickerPopoverRef = useRef<HTMLDivElement | null>(null);
  const datePickerTriggerRef = useRef<HTMLButtonElement | null>(null);
  const datePickerPopoverRef = useRef<HTMLDivElement | null>(null);
  const [anchoredPosition, setAnchoredPosition] = useState<{ top: number; left: number } | null>(null);
  const [anchorSide, setAnchorSide] = useState<"left" | "right" | null>(null);
  const [isColorPickerOpen, setIsColorPickerOpen] = useState(false);
  const [hexDraft, setHexDraft] = useState(DEFAULT_STATE.color);
  const [colorPickerPosition, setColorPickerPosition] = useState<{ top: number; left: number } | null>(
    null
  );
  const [isDatePickerOpen, setIsDatePickerOpen] = useState(false);
  const [datePickerPosition, setDatePickerPosition] = useState<{ top: number; left: number } | null>(null);
  const [selectedDate, setSelectedDate] = useState(() => startOfDay(referenceDate));
  const [monthDate, setMonthDate] = useState(() => startOfMonth(referenceDate));
  const activeEventId = activeEvent?.id;

  useEffect(() => {
    if (!isOpen) {
      return;
    }

    if (activeEvent) {
      dispatch({ type: "reset", payload: resolveStateFromEvent(activeEvent, calendarFallbackId) });
      return;
    }

    if (initialRange) {
      dispatch({
        type: "reset",
        payload: {
          ...DEFAULT_STATE,
          title: "",
          calendarId: calendarFallbackId,
          startTime: formatTimeInput(initialRange.start),
          endTime: formatTimeInput(initialRange.end),
          details: "",
          reminderMinutesBefore: null,
        },
      });
      return;
    }

    dispatch({
      type: "reset",
      payload: {
        ...DEFAULT_STATE,
        title: "",
        calendarId: calendarFallbackId,
        details: "",
        reminderMinutesBefore: null,
      },
    });
  }, [activeEvent, calendarFallbackId, initialRange, isOpen, referenceDate]);

  useLayoutEffect(() => {
    if (typeof window === "undefined") {
      return;
    }
    if (!isOpen || !anchorRect) {
      setAnchoredPosition(null);
      setAnchorSide(null);
      return;
    }

    const updatePosition = () => {
      if (!anchorRect) {
        setAnchoredPosition(null);
        setAnchorSide(null);
        return;
      }

      const card = cardRef.current;
      const cardRect = card?.getBoundingClientRect();
      const cardWidth = cardRect?.width ?? 360;
      const cardHeight = cardRect?.height ?? 420;
      const padding = 16;
      const maxLeft = Math.max(padding, window.innerWidth - padding - cardWidth);
      const preferredRight = anchorRect.left + anchorRect.width + padding;
      let left = Math.min(preferredRight, maxLeft);
      let side: "left" | "right" = "right";

      if (preferredRight > maxLeft) {
        const altLeft = anchorRect.left - cardWidth - padding;
        left = Math.min(Math.max(padding, altLeft), maxLeft);
        side = "left";
      } else {
        left = Math.max(padding, left);
      }

      let top = anchorRect.top + anchorRect.height / 2 - cardHeight / 2;
      const maxTop = Math.max(padding, window.innerHeight - padding - cardHeight);
      top = Math.min(Math.max(padding, top), maxTop);

      setAnchoredPosition({ top, left });
      setAnchorSide(side);
    };

    updatePosition();
    window.addEventListener("resize", updatePosition);
    return () => window.removeEventListener("resize", updatePosition);
  }, [anchorRect, isOpen, state.entryType, state.startTime, state.endTime, state.details, state.title]);

  const isHabit = state.entryType === "habit";
  const showReminderControl = state.entryType === "event";

  useEffect(() => {
    if (isHabit) {
      setIsDatePickerOpen(false);
    }
  }, [isHabit]);

  const handleSelectEntryType = (nextType: CalendarEntryType) => {
    if (state.entryType === nextType) {
      return;
    }
    const payload: Partial<ComposerState> = {
      entryType: nextType,
      color: DEFAULT_COLORS[nextType], // Apply default color for the new type
    };
    dispatch({ type: "update", payload });
  };

  const currentStart = useMemo(
    () => combineDateWithTime(selectedDate, state.startTime),
    [selectedDate, state.startTime]
  );
  const currentEnd = useMemo(() => {
    return combineDateWithTime(selectedDate, state.endTime);
  }, [currentStart, selectedDate, state.endTime]);

  const closeWithOptionalAutoCreate = useCallback(
    (options?: { allowAutoCreate?: boolean }) => {
      const allowAutoCreate = options?.allowAutoCreate ?? true;

      if (!allowAutoCreate) {
        onRequestClose();
        return;
      }

      const trimmedTitle = state.title.trim();

      if (activeEventId || trimmedTitle.length === 0) {
        onRequestClose();
        return;
      }

      const start = currentStart;
      const rawEnd = currentEnd;
      const normalizedEnd =
        rawEnd <= start
          ? new Date(start.getTime() + DEFAULT_EVENT_DURATION_MINUTES * 60000)
          : rawEnd;

      onSubmit({
        id: activeEvent?.id,
        title: trimmedTitle || t("Untitled"),
        start,
        end: normalizedEnd,
        color: state.color,
        entryType: state.entryType,
        calendarId: state.calendarId,
        description: state.details.trim() ? state.details.trim() : undefined,
        reminderMinutesBefore: showReminderControl ? state.reminderMinutesBefore : null,
      });

      onRequestClose();
    },
    [
      activeEvent,
      activeEventId,
      currentEnd,
      currentStart,
      onRequestClose,
      onSubmit,
      showReminderControl,
      state.calendarId,
      state.color,
      state.details,
      state.entryType,
      state.reminderMinutesBefore,
      state.title,
      t,
    ]
  );

  useEffect(() => {
    onStateChange?.(state);
  }, [state, onStateChange]);

  const handleSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    const start = currentStart;
    const rawEnd = currentEnd;
    const normalizedEnd =
      rawEnd <= start
        ? new Date(start.getTime() + DEFAULT_EVENT_DURATION_MINUTES * 60000)
        : rawEnd;

    onSubmit({
      id: activeEvent?.id,
      title: state.title.trim() || t("Untitled"),
      start,
      end: normalizedEnd,
      color: state.color,
      entryType: state.entryType,
      calendarId: state.calendarId,
      description: state.details.trim() ? state.details.trim() : undefined,
      reminderMinutesBefore: showReminderControl ? state.reminderMinutesBefore : null,
    });
    onRequestClose();
  };

  const handleDelete = useCallback(() => {
    if (!activeEventId) {
      return;
    }
    onDelete?.(activeEventId);
  }, [activeEventId, onDelete]);

  useEffect(() => {
    if (!isOpen) {
      return undefined;
    }

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        closeWithOptionalAutoCreate();
        return;
      }
      if (event.key === "Delete" && activeEventId) {
        event.preventDefault();
        handleDelete();
        return;
      }
      if (event.key === "Enter") {
        if (event.target instanceof HTMLTextAreaElement) {
          return;
        }
        event.preventDefault();
        formRef.current?.requestSubmit();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [activeEventId, closeWithOptionalAutoCreate, handleDelete, isOpen]);

  useEffect(() => {
    if (!isOpen) {
      setIsColorPickerOpen(false);
      setIsDatePickerOpen(false);
    }
  }, [isOpen]);

  useEffect(() => {
    setHexDraft(state.color);
  }, [state.color]);

  useEffect(() => {
    if (!isDatePickerOpen) return;

    const handlePointerDown = (event: globalThis.PointerEvent) => {
      if (isPointerEventInside(event, datePickerTriggerRef.current)) return;
      if (isPointerEventInside(event, datePickerPopoverRef.current)) return;
      setIsDatePickerOpen(false);
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") setIsDatePickerOpen(false);
    };

    document.addEventListener("pointerdown", handlePointerDown, { capture: true });
    document.addEventListener("keydown", handleKeyDown);

    return () => {
      document.removeEventListener("pointerdown", handlePointerDown, { capture: true });
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, [isDatePickerOpen]);

  useEffect(() => {
    if (!isColorPickerOpen) return;

    const handlePointerDown = (event: globalThis.PointerEvent) => {
      if (isPointerEventInside(event, colorPickerRef.current)) return;
      setIsColorPickerOpen(false);
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") setIsColorPickerOpen(false);
    };

    document.addEventListener("pointerdown", handlePointerDown, { capture: true });
    document.addEventListener("keydown", handleKeyDown);

    return () => {
      document.removeEventListener("pointerdown", handlePointerDown, { capture: true });
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, [isColorPickerOpen]);

  useLayoutEffect(() => {
    if (!isColorPickerOpen) {
      setColorPickerPosition(null);
      return;
    }

    const triggerRect = colorPickerTriggerRef.current?.getBoundingClientRect();
    if (!triggerRect) return;

    const popoverRect = colorPickerPopoverRef.current?.getBoundingClientRect();
    const popoverWidth = popoverRect?.width ?? 360;
    const popoverHeight = popoverRect?.height ?? 420;

    const viewportPadding = 12;
    const gap = 12;

    const spaceRight = window.innerWidth - triggerRect.right - gap;
    const spaceLeft = triggerRect.left - gap;

    let left = triggerRect.right + gap;
    if (spaceRight < popoverWidth && spaceLeft >= popoverWidth) {
      left = triggerRect.left - gap - popoverWidth;
    } else if (spaceRight < popoverWidth) {
      left = clamp(
        triggerRect.left - popoverWidth / 2,
        viewportPadding,
        window.innerWidth - viewportPadding - popoverWidth
      );
    }

    const top = clamp(
      triggerRect.top,
      viewportPadding,
      window.innerHeight - viewportPadding - popoverHeight
    );

    setColorPickerPosition({ top, left });
  }, [isColorPickerOpen]);

  useLayoutEffect(() => {
    if (!isDatePickerOpen) {
      setDatePickerPosition(null);
      return;
    }

    const viewportPadding = 12;
    const gap = 10;

    const updatePosition = () => {
      const triggerRect = datePickerTriggerRef.current?.getBoundingClientRect();
      if (!triggerRect) return;

      const popoverRect = datePickerPopoverRef.current?.getBoundingClientRect();
      const popoverWidth = popoverRect?.width ?? 320;
      const popoverHeight = popoverRect?.height ?? 340;

      const maxLeft = window.innerWidth - viewportPadding - popoverWidth;
      const preferredLeftOfTrigger = triggerRect.left - gap - popoverWidth;
      const preferredRightAligned = triggerRect.right - popoverWidth;

      const left =
        preferredLeftOfTrigger >= viewportPadding
          ? Math.min(preferredLeftOfTrigger, maxLeft)
          : clamp(preferredRightAligned, viewportPadding, maxLeft);

      const preferredTop = triggerRect.bottom + gap;
      const canPlaceBelow = preferredTop + popoverHeight <= window.innerHeight - viewportPadding;
      const top = canPlaceBelow
        ? preferredTop
        : clamp(
          triggerRect.top - gap - popoverHeight,
          viewportPadding,
          window.innerHeight - viewportPadding - popoverHeight
        );

      setDatePickerPosition({ top, left });
    };

    updatePosition();
    window.addEventListener("resize", updatePosition);
    return () => window.removeEventListener("resize", updatePosition);
  }, [isDatePickerOpen, monthDate]);

  const rgb = hexToRgb(state.color) ?? { red: 0, green: 0, blue: 0 };
  const colorPopoverStyle = useMemo<CSSProperties | undefined>(() => {
    if (!colorPickerPosition) return undefined;
    return { top: `${colorPickerPosition.top}px`, left: `${colorPickerPosition.left}px` };
  }, [colorPickerPosition]);

  const datePopoverStyle = useMemo<CSSProperties | undefined>(() => {
    if (!datePickerPosition) return undefined;
    return { top: `${datePickerPosition.top}px`, left: `${datePickerPosition.left}px` };
  }, [datePickerPosition]);

  if (!isOpen) {
    return null;
  }

  const handleSelectColor = (colorValue: string) => {
    dispatch({ type: "update", payload: { color: colorValue } });
    setIsColorPickerOpen(false);
  };

  const handleUpdateColorWithoutClosing = (colorValue: string) => {
    dispatch({ type: "update", payload: { color: colorValue } });
  };

  const handlePickCustomColor = () => {
    setIsColorPickerOpen((previous) => !previous);
  };

  const handleHexCommit = () => {
    const normalized = normalizeHex(hexDraft);
    if (!normalized) {
      setHexDraft(state.color);
      return;
    }
    handleSelectColor(normalized);
  };

  const overlayClassName = [
    styles.composerOverlay,
    anchoredPosition ? styles.composerOverlayAnchored : null,
  ]
    .filter(Boolean)
    .join(" ");

  const handleOverlayClick = (event: MouseEvent<HTMLDivElement>) => {
    if (event.target === event.currentTarget) {
      closeWithOptionalAutoCreate();
    }
  };

  return (
    <div
      className={overlayClassName}
      role="dialog"
      aria-modal="true"
      onClick={handleOverlayClick}
    >
      <div
        ref={cardRef}
        className={styles.composerCard}
        data-anchored={anchoredPosition ? "true" : "false"}
        data-anchor-side={anchorSide ?? undefined}
        style={
          anchoredPosition
            ? {
              position: "fixed",
              top: `${anchoredPosition.top}px`,
              left: `${anchoredPosition.left}px`,
            }
            : undefined
        }
      >
        <div className={styles.composerHeader}>
          <div className={styles.composerHeaderTypeSelect}>
            <select
              value={state.entryType}
              onChange={(event) =>
                handleSelectEntryType(event.target.value as CalendarEntryType)
              }
              className={styles.composerHeaderSelect}
            >
              {(() => {
                const entryTypes = VISIBLE_ENTRY_TYPES.includes(state.entryType)
                  ? VISIBLE_ENTRY_TYPES
                  : [state.entryType, ...VISIBLE_ENTRY_TYPES];
                return entryTypes.map((type) => (
                  <option
                    key={type}
                    value={type}
                    disabled={!VISIBLE_ENTRY_TYPES.includes(type)}
                  >
                    {t(ENTRY_TYPE_LABELS[type])}
                  </option>
                ));
              })()}
            </select>
            <ChevronDown size={16} className={styles.composerHeaderSelectArrow} />
          </div>
          <button
            type="button"
            onClick={() => closeWithOptionalAutoCreate()}
            aria-label={t("Close dialog")}
            className={styles.composerCloseButton}
          >
            <X size={18} strokeWidth={1.75} />
          </button>
        </div>

        <form ref={formRef} onSubmit={handleSubmit} className={styles.composerForm}>
          <button type="submit" style={{ display: "none" }} aria-hidden="true" tabIndex={-1} />
          <div className={styles.composerTitleRow}>
            <input
              type="text"
              value={state.title}
              onChange={(event) =>
                dispatch({ type: "update", payload: { title: event.target.value } })
              }
              placeholder={t("Title")}
              className={styles.composerTitleInput}
            />
          </div>
          {!isHabit ? (
            <>
              <div className={styles.composerTimeSection}>
                <div className={styles.composerTimeRow}>
                  <div className={styles.composerTimeInputGroup}>
                    <input
                      type="time"
                      value={state.startTime}
                      onChange={(event) =>
                        dispatch({ type: "update", payload: { startTime: event.target.value } })
                      }
                      className={styles.composerTimeInput}
                      required
                    />
                    <ArrowRight size={14} className={styles.composerTimeArrow} />
                    <input
                      type="time"
                      value={state.endTime}
                      onChange={(event) =>
                        dispatch({ type: "update", payload: { endTime: event.target.value } })
                      }
                      className={styles.composerTimeInput}
                      required
                    />
                  </div>
	                  <span className={styles.composerDuration}>
	                    {(() => {
	                      const start = new Date(`2000-01-01T${state.startTime}`);
	                      const end = new Date(`2000-01-01T${state.endTime}`);
	                      let diff = end.getTime() - start.getTime();
	                      if (diff < 0) diff += 24 * 60 * 60 * 1000;
	                      const mins = Math.floor(diff / 60000);
	                      const h = Math.floor(mins / 60);
	                      const m = mins % 60;
	                      if (h <= 0) {
	                        return `${mins}m`;
	                      }
	                      if (m === 0) {
	                        return `${h}h`;
	                      }
	                      return `${h}h ${m}m`;
	                    })()}
	                  </span>
                </div>
                {showReminderControl ? (
                  <div className={styles.composerField}>
                    <span>{t("Notification")}</span>
                    <select
                      value={state.reminderMinutesBefore === null ? "" : String(state.reminderMinutesBefore)}
                      onChange={(event) => {
                        const raw = event.target.value;
                        const next = raw ? Number.parseInt(raw, 10) : null;
                        dispatch({
                          type: "update",
                          payload: {
                            reminderMinutesBefore: Number.isFinite(next) ? next : null,
                          },
                        });
                      }}
                    >
                      <option value="">{t("No reminder")}</option>
                      <option value="0">{t("When event starts")}</option>
                      <option value="5">{t("5 minutes before")}</option>
                      <option value="10">{t("10 minutes before")}</option>
                      <option value="15">{t("15 minutes before")}</option>
                      <option value="30">{t("30 minutes before")}</option>
                      <option value="60">{t("1 hour before")}</option>
                    </select>
                  </div>
                ) : null}
                <div className={styles.composerDateRow}>
                  <button
                    type="button"
                    className={styles.composerDateTrigger}
                    onClick={() => {
                      setMonthDate(startOfMonth(selectedDate));
                      setIsDatePickerOpen((previous) => !previous);
                    }}
                    aria-expanded={isDatePickerOpen ? "true" : "false"}
                    aria-label={t("Choose date")}
                    ref={datePickerTriggerRef}
                  >
                    <Calendar
                      size={14}
                      aria-hidden="true"
                      className={styles.composerInlineControlIcon}
                    />
                    <span className={styles.composerInlineControlLabel}>
                      {selectedDate.toLocaleDateString(undefined, {
                        weekday: "short",
                        month: "short",
                        day: "numeric",
                      })}
                    </span>
                    <ChevronDown
                      size={14}
                      aria-hidden="true"
                      className={styles.composerInlineControlChevron}
                    />
                  </button>
                </div>
              </div>
            </>
          ) : null}

          {isDatePickerOpen ? (
            <div
              ref={datePickerPopoverRef}
              className={styles.composerDatePopover}
              style={datePopoverStyle}
              role="dialog"
              aria-label={t("Date picker")}
            >
              <div className={styles.composerDatePopoverHeader}>
                <span className={styles.composerDatePopoverMonthLabel}>
                  {monthDate.toLocaleDateString(undefined, { month: "long", year: "numeric" })}
                </span>
                <span className={styles.composerDatePopoverControls}>
                  <button
                    type="button"
                    className={styles.composerDatePopoverNavButton}
                    aria-label={t("Previous")}
                    title={t("Go to previous month")}
                    onClick={() =>
                      setMonthDate((previous) => {
                        const next = startOfMonth(previous);
                        next.setMonth(previous.getMonth() - 1);
                        return next;
                      })
                    }
                  >
                    <ChevronLeft size={14} />
                  </button>
                  <button
                    type="button"
                    className={styles.composerDatePopoverNavButton}
                    aria-label={t("Next")}
                    title={t("Go to next month")}
                    onClick={() =>
                      setMonthDate((previous) => {
                        const next = startOfMonth(previous);
                        next.setMonth(previous.getMonth() + 1);
                        return next;
                      })
                    }
                  >
                    <ChevronRight size={14} />
                  </button>
                </span>
              </div>

              <div className={styles.composerMiniCalendarCompact}>
                <MiniMonth
                  referenceDate={monthDate}
                  selectedDate={selectedDate}
                  onSelectDate={(nextDate) => {
                    const normalized = startOfDay(nextDate);
                    setSelectedDate(normalized);
                    if (
                      normalized.getMonth() !== monthDate.getMonth() ||
                      normalized.getFullYear() !== monthDate.getFullYear()
                    ) {
                      setMonthDate(startOfMonth(normalized));
                    }
                    setIsDatePickerOpen(false);
                  }}
                />
              </div>
            </div>
          ) : null}

          <label className={styles.composerField}>
            <textarea
              value={state.details}
              onChange={(event) =>
                dispatch({ type: "update", payload: { details: event.target.value } })
              }
              placeholder={t("Description")}
              rows={3}
              aria-label={t("Description")}
            />
          </label>

          <div className={styles.composerField}>
            <span>{t("Color")}</span>
            <div className={styles.composerColorRow}>
              <div className={styles.composerColors} ref={colorPickerRef}>
                <div className={styles.composerQuickSwatches}>
                  {QUICK_COLOR_SWATCHES.map((swatch) => (
                    <button
                      key={swatch}
                      type="button"
                      className={styles.composerColorDot}
                      style={{ backgroundColor: swatch }}
                      data-active={state.color === swatch ? "true" : "false"}
                      onClick={() => handleSelectColor(swatch)}
                      aria-label={t("Select {color} color", { color: swatch })}
                    />
                  ))}
                </div>
                <button
                  type="button"
                  className={styles.composerColorDot}
                  data-active={
                    QUICK_COLOR_SWATCHES.includes(state.color as (typeof QUICK_COLOR_SWATCHES)[number])
                      ? "false"
                      : "true"
                  }
                  onClick={handlePickCustomColor}
                  aria-label={t("Pick custom color")}
                  aria-expanded={isColorPickerOpen ? "true" : "false"}
                  ref={colorPickerTriggerRef}
                >
                  <Plus size={18} strokeWidth={1.75} aria-hidden="true" />
                </button>

                {isColorPickerOpen ? (
                  <div
                    ref={colorPickerPopoverRef}
                    className={styles.composerColorPopover}
                    style={colorPopoverStyle}
                    role="dialog"
                    aria-label={t("Color picker")}
                  >
                    <div className={styles.composerColorPopoverHeader}>
                      <div
                        className={styles.composerColorPreview}
                        style={{ backgroundColor: state.color }}
                        aria-hidden="true"
                      />
                      <label className={styles.composerColorHexLabel}>
                        <span>HEX</span>
                        <input
                          value={hexDraft}
                          onChange={(event) => setHexDraft(event.target.value)}
                          onBlur={handleHexCommit}
                          onKeyDown={(event) => {
                            if (event.key === "Enter") {
                              event.preventDefault();
                              handleHexCommit();
                            }
                          }}
                          inputMode="text"
                          autoComplete="off"
                          spellCheck={false}
                        />
                      </label>
                    </div>

                    <div className={styles.composerColorSliders} aria-label={t("RGB sliders")}>
                      <label>
                        <span>R</span>
                        <input
                          type="range"
                          min={0}
                          max={255}
                          value={rgb.red}
                          onChange={(event) => handleUpdateColorWithoutClosing(rgbToHex(Number(event.target.value), rgb.green, rgb.blue))}
                        />
                        <output>{rgb.red}</output>
                      </label>
                      <label>
                        <span>G</span>
                        <input
                          type="range"
                          min={0}
                          max={255}
                          value={rgb.green}
                          onChange={(event) => handleUpdateColorWithoutClosing(rgbToHex(rgb.red, Number(event.target.value), rgb.blue))}
                        />
                        <output>{rgb.green}</output>
                      </label>
                      <label>
                        <span>B</span>
                        <input
                          type="range"
                          min={0}
                          max={255}
                          value={rgb.blue}
                          onChange={(event) => handleUpdateColorWithoutClosing(rgbToHex(rgb.red, rgb.green, Number(event.target.value)))}
                        />
                        <output>{rgb.blue}</output>
                      </label>
                    </div>

                    <div className={styles.composerColorPaletteSection}>
                      <h3>Earthy</h3>
                      <div className={styles.composerColorPaletteGrid}>
                        {EARTHY_PALETTE.map((swatch) => (
                          <button
                            key={`earthy-${swatch}`}
                            type="button"
                            className={styles.composerColorSwatch}
                            style={{ backgroundColor: swatch }}
                            data-active={state.color === swatch ? "true" : "false"}
                            onClick={() => handleSelectColor(swatch)}
                            aria-label={t("Select {color} color", { color: swatch })}
                          />
                        ))}
                      </div>
                    </div>

                    <div className={styles.composerColorPaletteSection}>
                      <h3>Pastel</h3>
                      <div className={styles.composerColorPaletteGrid}>
                        {PASTEL_PALETTE.map((swatch) => (
                          <button
                            key={`pastel-${swatch}`}
                            type="button"
                            className={styles.composerColorSwatch}
                            style={{ backgroundColor: swatch }}
                            data-active={state.color === swatch ? "true" : "false"}
                            onClick={() => handleSelectColor(swatch)}
                            aria-label={t("Select {color} color", { color: swatch })}
                          />
                        ))}
                      </div>
                    </div>

                    <div className={styles.composerColorPaletteSection}>
                      <h3>Neutrals</h3>
                      <div className={styles.composerColorPaletteGrid}>
                        {NEUTRAL_PALETTE.map((swatch) => (
                          <button
                            key={`neutral-${swatch}`}
                            type="button"
                            className={styles.composerColorSwatch}
                            style={{ backgroundColor: swatch }}
                            data-active={state.color === swatch ? "true" : "false"}
                            onClick={() => handleSelectColor(swatch)}
                            aria-label={t("Select {color} color", { color: swatch })}
                          />
                        ))}
                      </div>
                    </div>
                  </div>
                ) : null}
              </div>

              <div className={styles.composerFooter}>
                {activeEvent && onDelete ? (
                  <button type="button" className={styles.composerDeleteButton} onClick={handleDelete}>
                    {t("Delete")}
                  </button>
                ) : null}
                <button type="submit">
                  {activeEvent ? t("Save") : t("Add")}
                </button>
              </div>
            </div>
          </div>

        </form>
      </div>
    </div>
  );
}

"use client";

import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ChangeEvent,
  type CSSProperties,
  type MouseEvent,
  type ReactNode,
} from "react";

import styles from "./GrayDashboardCalendar.module.css";
import { CalendarSidebar } from "./CalendarSidebar";
import { EventCard } from "./EventCard";
import {
  EventComposer,
  EventComposerPayload,
  ComposerState,
} from "./EventComposer";
import { layoutDayEvents } from "./layoutDayEvents";
import { useEventDrag } from "./useEventDrag";
import { useEventResize } from "./useEventResize";
import {
  CalendarEvent,
  CalendarInfo,
  EventDraft,
  PositionedEvent,
} from "./types";
import { createSeedCalendars, createSeedEvents } from "./calendarSeed";
import type { DashboardHeaderProps } from "@/components/gray/DashboardHeader";
import { ViewModeSelect } from "@/components/gray/ViewModeSelect";
import { useI18n } from "@/contexts/I18nContext";

const HOURS = Array.from({ length: 24 }, (_, index) => index);
const DEFAULT_HOUR_HEIGHT = 64;
const SNAP_MINUTES = 15;
const TIMELINE_WIDTH = 56;

type CalendarViewMode = "week" | "day";
type ComposerAnchorRect = {
  top: number;
  left: number;
  width: number;
  height: number;
};

const startOfDay = (value: Date) => {
  const result = new Date(value);
  result.setHours(0, 0, 0, 0);
  return result;
};

const startOfWeek = (value: Date) => {
  const result = startOfDay(value);
  result.setDate(result.getDate() - result.getDay());
  return result;
};

const isSameDay = (a: Date, b: Date) =>
  a.getFullYear() === b.getFullYear() &&
  a.getMonth() === b.getMonth() &&
  a.getDate() === b.getDate();

const formatWeekRange = (reference: Date) => {
  const start = startOfWeek(reference);
  const end = new Date(start);
  end.setDate(start.getDate() + 6);

  const formatter = new Intl.DateTimeFormat(undefined, {
    month: "long",
    day: "numeric",
  });

  const startLabel = formatter.format(start);
  const endLabel = formatter.format(end);
  const year = end.getFullYear();
  return `${startLabel} — ${endLabel}, ${year}`;
};

const formatDayLabel = (value: Date) =>
  value.toLocaleDateString(undefined, {
    weekday: "long",
    month: "long",
    day: "numeric",
  });

const HOURS_LABEL = HOURS.map((hour) => {
  if (hour === 0) return "12 AM";
  if (hour < 12) return `${hour} AM`;
  if (hour === 12) return "12 PM";
  return `${hour - 12} PM`;
});

const ensureDateZone = (value: Date) => new Date(value.getTime());

type GrayDashboardCalendarProps = {
  initialDate?: Date;
  viewModeLocked?: CalendarViewMode;
  showSidebar?: boolean;
  events?: CalendarEvent[];
  calendars?: CalendarInfo[];
  onEventsChange?: (events: CalendarEvent[]) => void;
  onCalendarsChange?: (calendars: CalendarInfo[]) => void;
  hourHeight?: number;
  maxHeight?: number | string;
  showSelectedDateLabel?: boolean;
  showSurfaceLabel?: boolean;
  showSurfaceHeading?: boolean;
  showHeaderControls?: boolean;
  showCalendarList?: boolean;
  showHeaderDates?: boolean;
  compactSurface?: boolean;
  className?: string;
  surfaceClassName?: string;
  showTodayButton?: boolean;
  onIntegrationAction?: () => void;
  dashboardTab?: "pulse" | "calendar";
  onSelectDashboardTab?: (tab: "pulse" | "calendar") => void;
  renderHeader?: (props: DashboardHeaderProps) => ReactNode;
  embedWithinParentSurface?: boolean;
  currentDate?: Date;
  selectedDate?: Date;
  onSelectedDateChange?: (date: Date) => void;
  onEventDelete?: (event: CalendarEvent) => void;
  onCreatePlan?: (payload: EventComposerPayload) => void;
  onCreateHabit?: (payload: EventComposerPayload) => void;
};

export function GrayDashboardCalendar({
  initialDate,
  viewModeLocked,
  showSidebar = true,
  events: externalEvents,
  calendars: externalCalendars,
  onEventsChange,
  onCalendarsChange,
  hourHeight: hourHeightProp,
  maxHeight,
  showSelectedDateLabel = true,
  showSurfaceLabel = true,
  showSurfaceHeading = true,
  showHeaderControls = true,
  showCalendarList = true,
  showHeaderDates = true,
  compactSurface = false,
  className,
  surfaceClassName,
  showTodayButton = true,
  onIntegrationAction,
  dashboardTab = "calendar",
  onSelectDashboardTab,
  renderHeader,
  embedWithinParentSurface = false,
  currentDate,
  selectedDate: controlledSelectedDate,
  onSelectedDateChange,
  onEventDelete,
  onCreatePlan,
  onCreateHabit,
}: GrayDashboardCalendarProps) {
  const { t } = useI18n();
  const hourHeight = hourHeightProp ?? DEFAULT_HOUR_HEIGHT;
  const [viewMode, setViewMode] = useState<CalendarViewMode>(viewModeLocked ?? "week");
  const initial = initialDate ? new Date(initialDate) : new Date();

  const [internalSelectedDate, setInternalSelectedDate] = useState(() => controlledSelectedDate ?? initial);
  const selectedDate = controlledSelectedDate ?? internalSelectedDate;

  const [monthDate, setMonthDate] = useState(() => selectedDate);
  const [calendarsState, setCalendarsState] = useState<CalendarInfo[]>(createSeedCalendars);
  const [eventsState, setEventsState] = useState<CalendarEvent[]>(createSeedEvents);
  const [composerOpen, setComposerOpen] = useState(false);
  const [editingEvent, setEditingEvent] = useState<CalendarEvent | null>(null);

  // Multi-select state
  const [selectedEventIds, setSelectedEventIds] = useState<Set<string>>(new Set());


  const [nowReference, setNowReference] = useState<Date | null>(() => currentDate ?? null);
  const [composerRange, setComposerRange] = useState<{ start: Date; end: Date } | null>(null);
  const [composerAnchorRect, setComposerAnchorRect] = useState<ComposerAnchorRect | null>(null);


  const dayColumnRef = useRef<HTMLDivElement | null>(null);
  const weekScrollRef = useRef<HTMLDivElement | null>(null);
  const weekColumnsRef = useRef<HTMLDivElement | null>(null);
  const hasInitialDayScrollRef = useRef(false);
  const hasInitialWeekScrollRef = useRef(false);

  const touchStartRef = useRef<{ x: number; y: number } | null>(null);

  useEffect(() => {
    if (controlledSelectedDate) {
      setMonthDate(controlledSelectedDate);
    }
  }, [controlledSelectedDate]);

  const calendars = externalCalendars ?? calendarsState;
  const events = externalEvents ?? eventsState;

  const updateCalendars = (updater: (previous: CalendarInfo[]) => CalendarInfo[]) => {
    if (externalCalendars && onCalendarsChange) {
      onCalendarsChange(updater(externalCalendars));
      return;
    }
    setCalendarsState((previous) => {
      const next = updater(previous);
      onCalendarsChange?.(next);
      return next;
    });
  };

  const updateEvents = (updater: (previous: CalendarEvent[]) => CalendarEvent[]) => {
    if (externalEvents && onEventsChange) {
      onEventsChange(updater(externalEvents));
      return;
    }
    setEventsState((previous) => {
      const next = updater(previous);
      onEventsChange?.(next);
      return next;
    });
  };

  const handleCommitDrag = (drafts: Record<string, EventDraft>) => {
    updateEvents((previous) =>
      previous.map((event) => {
        const draft = drafts[event.id];
        if (draft) {
          return {
            ...event,
            start: ensureDateZone(draft.start),
            end: ensureDateZone(draft.end),
          };
        }
        return event;
      })
    );
  };

  const dragControls = useEventDrag({
    containerRef: dayColumnRef,
    hourHeight,
    snapMinutes: SNAP_MINUTES,
    selectedEventIds,
    allEvents: events,
    onCommit: handleCommitDrag,
  });
  const {
    getDraggableProps,
    suppressClickRef: daySuppressClickRef,
    activeDrafts: dayDragDrafts,
  } = dragControls;

  const resizeControls = useEventResize({
    containerRef: dayColumnRef,
    hourHeight,
    snapMinutes: SNAP_MINUTES,
    onCommit: handleCommitDrag,
  });
  const {
    getResizeProps,
    activeDraft: blockResizeDraft,
  } = resizeControls;

  // We only support resizing single blocks for now, simpler
  const dayResizeDrafts = blockResizeDraft ? { [blockResizeDraft.id]: blockResizeDraft } : null;
  const dayDrafts = useMemo(() => {
    // Resize takes precedence if active
    if (dayResizeDrafts) return dayResizeDrafts;
    return dayDragDrafts;
  }, [dayDragDrafts, dayResizeDrafts]);

  // Week view drag with horizontal support
  const weekDragControls = useEventDrag({
    containerRef: weekScrollRef,
    hourHeight,
    snapMinutes: SNAP_MINUTES,
    selectedEventIds,
    allEvents: events,
    onCommit: handleCommitDrag,
    horizontal: {
      columnCount: 7,
      getColumnIndex: (pointerEvent: PointerEvent) => {
        const weekColumnsEl = weekColumnsRef.current;
        if (!weekColumnsEl) return 0;

        const rect = weekColumnsEl.getBoundingClientRect();
        const columnWidth = rect.width / 7;
        const relativeX = pointerEvent.clientX - rect.left;
        return Math.max(0, Math.min(6, Math.floor(relativeX / columnWidth)));
      },
    },
  });
  const {
    getDraggableProps: getWeekDraggableProps,
    suppressClickRef: weekSuppressClickRef,
    activeDrafts: weekDrafts,
  } = weekDragControls;

  const activeDrafts = dayDrafts || weekDrafts;

  const dayAnchor = useMemo(() => startOfDay(selectedDate), [selectedDate]);
  const weekAnchor = useMemo(() => startOfWeek(selectedDate), [selectedDate]);

  const calendarMap = useMemo(() => new Map(calendars.map((calendar) => [calendar.id, calendar])), [calendars]);

  const shortEventMinimumHeight = useMemo(
    () => Math.max(Math.round(hourHeight / 4), 12),
    [hourHeight]
  );

  const visibleEvents = useMemo(
    () => events.filter((event) => {
      // For regular events, check if their calendar is visible
      return calendarMap.get(event.calendarId)?.isVisible !== false;
    }),
    [calendarMap, events]
  );

  const weekDays = useMemo(
    () =>
      Array.from({ length: 7 }, (_, index) => {
        const date = new Date(weekAnchor);
        date.setDate(weekAnchor.getDate() + index);
        return date;
      }),
    [weekAnchor]
  );

  const timeZoneLabel = useMemo(() => {
    const formatter = new Intl.DateTimeFormat(undefined, { timeZoneName: "short" });
    const parts = formatter.formatToParts(new Date());
    const zone = parts.find((part) => part.type === "timeZoneName")?.value;
    return zone ?? Intl.DateTimeFormat().resolvedOptions().timeZone;
  }, []);

  const [composerDraft, setComposerDraft] = useState<ComposerState | null>(null);

  const composerPreviewEvent = useMemo<CalendarEvent | null>(() => {
    if (!composerOpen || !composerRange) {
      return null;
    }
    const draftTitle = composerDraft?.title?.trim();
    return {
      id: "composer-preview",
      title: draftTitle ? draftTitle : "",
      start: composerRange.start,
      end: composerRange.end,
      color: composerDraft?.color || "#3D6F73",
      entryType: composerDraft?.entryType || "event",
      calendarId: "preview",
      isAllDay: false,
    };
  }, [composerOpen, composerRange, composerDraft]);

  const dayEvents = useMemo(() => {
    const filtered = visibleEvents.filter((event) => isSameDay(event.start, selectedDate));
    let result = filtered;

    if (activeDrafts) {
      result = result.map((event) => {
        const draft = activeDrafts[event.id];
        if (draft) {
          return {
            ...event,
            start: ensureDateZone(draft.start),
            end: ensureDateZone(draft.end),
          };
        }
        return event;
      });
    }

    if (composerPreviewEvent && isSameDay(composerPreviewEvent.start, selectedDate)) {
      result = [...result, composerPreviewEvent];
    }

    return result;
  }, [activeDrafts, selectedDate, visibleEvents, composerPreviewEvent]);

  const dayLayouts = useMemo<PositionedEvent[]>(
    () =>
      layoutDayEvents(dayEvents, {
        hourHeight,
        minimumHeight: shortEventMinimumHeight,
        dayStart: dayAnchor,
      }),
    [dayAnchor, dayEvents, hourHeight, shortEventMinimumHeight]
  );

  const weekLayouts = useMemo(() => {
    return weekDays.map((day) => {
      const dayEventsForWeek = visibleEvents.filter((event) => isSameDay(event.start, day));
      const mappedEvents = activeDrafts
        ? dayEventsForWeek.map((event) => {
          const draft = activeDrafts[event.id];
          if (draft) {
            return {
              ...event,
              start: ensureDateZone(draft.start),
              end: ensureDateZone(draft.end),
            };
          }
          return event;
        })
        : dayEventsForWeek;

      const eventsWithPreview = mappedEvents.filter((event) => isSameDay(event.start, day));

      // Also add any active drafts if they belong to this day but weren't originally
      if (activeDrafts) {
        Object.values(activeDrafts).forEach((draft) => {
          if (isSameDay(draft.start, day) && !dayEventsForWeek.some((e) => e.id === draft.id)) {
            const originalEvent = visibleEvents.find((e) => e.id === draft.id);
            if (originalEvent) {
              eventsWithPreview.push({
                ...originalEvent,
                start: ensureDateZone(draft.start),
                end: ensureDateZone(draft.end),
              });
            }
          }
        });
      }

      if (composerPreviewEvent && isSameDay(composerPreviewEvent.start, day)) {
        eventsWithPreview.push(composerPreviewEvent);
      }

      return layoutDayEvents(eventsWithPreview, {
        hourHeight,
        minimumHeight: shortEventMinimumHeight,
        dayStart: startOfDay(day),
      });
    });
  }, [hourHeight, shortEventMinimumHeight, visibleEvents, weekDays, activeDrafts, composerPreviewEvent]);

  const updateViewMode = useCallback(
    (nextMode: CalendarViewMode) => {
      if (viewModeLocked) {
        return;
      }
      setViewMode(nextMode);
    },
    [viewModeLocked]
  );

  const handleViewModeChange = (event: ChangeEvent<HTMLSelectElement>) => {
    updateViewMode(event.target.value as CalendarViewMode);
  };

  const rangeNavigationLabel = viewMode === "week" ? t("Week") : t("Day");
  const shouldShowDashboardToggle = typeof onSelectDashboardTab === "function";

  useEffect(() => {
    if (currentDate) {
      setNowReference(currentDate);
    } else {
      const syncNow = () => setNowReference(new Date());
      syncNow();
      const interval = window.setInterval(syncNow, 60000);
      return () => window.clearInterval(interval);
    }
  }, [currentDate]);

  const getNowOffset = useCallback(
    (reference: Date) => {
      const minutes = reference.getHours() * 60 + reference.getMinutes() + reference.getSeconds() / 60;
      const offset = (minutes / 60) * hourHeight;
      const maxOffset = hourHeight * 24;
      return Math.min(Math.max(offset, 0), maxOffset);
    },
    [hourHeight]
  );

  const showDayNowIndicator = useMemo(
    () => (nowReference ? isSameDay(nowReference, selectedDate) : false),
    [nowReference, selectedDate]
  );

  const dayIndicatorOffset = useMemo(
    () => (showDayNowIndicator && nowReference ? getNowOffset(nowReference) : null),
    [showDayNowIndicator, nowReference, getNowOffset]
  );

  const weekNowIndicator = useMemo(() => {
    if (!nowReference) {
      return null;
    }
    const dayIndex = weekDays.findIndex((day) => isSameDay(day, nowReference));
    if (dayIndex === -1) {
      return null;
    }
    return {
      offset: getNowOffset(nowReference),
      dayIndex,
    };
  }, [getNowOffset, nowReference, weekDays]);



  useEffect(() => {
    // Only auto-scroll once on initial mount, never interfere with user scrolling
    if (hasInitialDayScrollRef.current || viewMode !== "day") {
      return;
    }
    const container = dayColumnRef.current;
    if (!container) {
      return;
    }

    // Scroll to current time indicator if available
    if (dayIndicatorOffset !== null) {
      const target = Math.max(dayIndicatorOffset - hourHeight, 0);
      container.scrollTo({ top: target });
      hasInitialDayScrollRef.current = true;
      return;
    }

    // Otherwise scroll to first event or top
    if (!dayLayouts.length) {
      return;
    }

    const earliestTop = dayLayouts.reduce(
      (min, event) => Math.min(min, event.top),
      Number.POSITIVE_INFINITY
    );
    const target = Math.max(earliestTop - hourHeight, 0);
    container.scrollTo({ top: target });
    hasInitialDayScrollRef.current = true;
  }, [dayIndicatorOffset, dayLayouts, hourHeight, viewMode]);

  useEffect(() => {
    // Only auto-scroll once on initial mount, never interfere with user scrolling
    if (hasInitialWeekScrollRef.current || viewMode !== "week") {
      return;
    }
    const container = weekScrollRef.current;
    if (!container || !weekNowIndicator) {
      return;
    }
    const target = Math.max(weekNowIndicator.offset - hourHeight, 0);
    container.scrollTo({ top: target });
    hasInitialWeekScrollRef.current = true;
  }, [hourHeight, viewMode, weekNowIndicator]);



  const handleToggleCalendar = (calendarId: string) => {
    updateCalendars((previous) =>
      previous.map((calendar) =>
        calendar.id === calendarId
          ? { ...calendar, isVisible: !calendar.isVisible }
          : calendar
      )
    );
  };

  const openComposerAt = useCallback(
    (startDate: Date, anchorRect?: ComposerAnchorRect | null) => {
      // startDate is already snapped from handleColumnClick, just copy it
      const alignedStart = new Date(startDate);
      // Ensure seconds/ms are cleared (they should be, but be defensive)
      alignedStart.setSeconds(0, 0);
      const alignedEnd = new Date(alignedStart.getTime() + 30 * 60000);
      setComposerRange({ start: alignedStart, end: alignedEnd });
      setEditingEvent(null);
      setComposerAnchorRect(anchorRect ?? null);
      setComposerOpen(true);
      // Clear selection when opening composer
      setSelectedEventIds(new Set());
    },
    []
  );

  const isGoogleCalendarEvent = (event: CalendarEvent) =>
    typeof event.calendarId === "string" && event.calendarId.startsWith("google:");

  const handleEventClick = (
    event: CalendarEvent,
    anchorRect?: DOMRect | DOMRectReadOnly | null,
    mouseEvent?: MouseEvent
  ) => {
    if (daySuppressClickRef.current || weekSuppressClickRef.current) return;

    if (mouseEvent?.ctrlKey || mouseEvent?.metaKey) {
      // Toggle selection
      setSelectedEventIds((prev) => {
        const next = new Set(prev);
        if (next.has(event.id)) {
          next.delete(event.id);
        } else {
          next.add(event.id);
        }
        return next;
      });
    } else {
      // Single select and edit
      setSelectedEventIds(new Set([event.id]));
      if (isGoogleCalendarEvent(event)) {
        return;
      }
      handleEditEvent(event, anchorRect);
    }
  };

  const handleEditEvent = (event: CalendarEvent, anchorRect?: DOMRect | DOMRectReadOnly | null) => {
    setEditingEvent(event);
    setComposerOpen(true);
    setComposerRange(null);
    if (anchorRect) {
      setComposerAnchorRect({
        top: anchorRect.top,
        left: anchorRect.left,
        width: anchorRect.width,
        height: anchorRect.height,
      });
    } else {
      setComposerAnchorRect(null);
    }
  };

  const handleComposerSubmit = ({ id, ...payload }: EventComposerPayload) => {
    if (payload.entryType === "plan" && onCreatePlan) {
      onCreatePlan({ id, ...payload });
      setComposerOpen(false);
      setEditingEvent(null);
      setComposerRange(null);
      setComposerAnchorRect(null);
      return;
    }

    if (payload.entryType === "habit" && onCreateHabit) {
      onCreateHabit({ id, ...payload });
      setComposerOpen(false);
      setEditingEvent(null);
      setComposerRange(null);
      setComposerAnchorRect(null);
      return;
    }

    updateEvents((previous) => {
      if (id) {
        return previous.map((event) =>
          event.id === id
            ? {
              ...event,
              ...payload,
            }
            : event
        );
      }

      const newEvent: CalendarEvent = {
        id: `evt-${Date.now()}`,
        ...payload,
      };
      return [...previous, newEvent];
    });
    setComposerOpen(false);
    setEditingEvent(null);
    setComposerRange(null);
    setComposerAnchorRect(null);
  };

  const handleComposerDelete = (eventId: string) => {
    const eventToDelete = events.find((event) => event.id === eventId);
    if (eventToDelete && onEventDelete) {
      onEventDelete(eventToDelete);
    }
    updateEvents((previous) => previous.filter((event) => event.id !== eventId));
    setComposerOpen(false);
    setEditingEvent(null);
    setComposerRange(null);
    setComposerAnchorRect(null);
  };

  const handleColumnClick = (event: MouseEvent<HTMLDivElement>, day: Date) => {
    if (daySuppressClickRef.current || weekSuppressClickRef.current) {
      return;
    }
    const target = event.currentTarget;
    if (event.target instanceof HTMLElement) {
      // Ignore clicks that originate from an existing event card so we don't
      // create a new draft on top of the one being edited.
      if (event.target.closest(`.${styles.eventCard}`)) {
        return;
      }
    }

    // Clear selection on background click
    setSelectedEventIds(new Set());

    const bounds = target.getBoundingClientRect();
    const offsetY = event.clientY - bounds.top;
    const totalMinutes = Math.max(0, Math.min(24 * 60 - 1, Math.round((offsetY / hourHeight) * 60 / SNAP_MINUTES) * SNAP_MINUTES));
    const hours = Math.floor(totalMinutes / 60);
    const minutes = totalMinutes % 60;
    const start = new Date(day);
    start.setHours(hours, minutes, 0, 0);

    const startMinutes = hours * 60 + minutes;
    const startOffsetPx = (startMinutes / 60) * hourHeight;
    const defaultDurationMinutes = 60; // Default event length
    const eventHeightPx = (defaultDurationMinutes / 60) * hourHeight;

    const anchorRect: ComposerAnchorRect = {
      left: bounds.left,
      width: bounds.width,
      top: bounds.top + startOffsetPx,
      height: eventHeightPx,
    };
    openComposerAt(start, anchorRect);
  };

  // Helper to override event position if dragged
  const getEventOverride = (event: PositionedEvent, dayStart: Date) => {
    const draft = activeDrafts?.[event.id];
    if (!draft) return event;

    const startMinutes = (draft.start.getTime() - dayStart.getTime()) / 60000;
    const endMinutes = (draft.end.getTime() - dayStart.getTime()) / 60000;
    const durationMinutes = Math.max(endMinutes - startMinutes, 5);

    const minuteHeight = hourHeight / 60;
    const top = Math.max(startMinutes * minuteHeight, 0);
    const height = Math.max(durationMinutes * minuteHeight, shortEventMinimumHeight);

    return {
      ...event,
      top,
      height,
    };
  };

  const handleDeleteEvent = (event: PositionedEvent) => {
    const calendarEvent = events.find((e) => e.id === event.id);
    if (calendarEvent && onEventDelete) {
      onEventDelete(calendarEvent);
    }
    updateEvents((previous) => previous.filter((e) => e.id !== event.id));
  };

  const calendarGridStyle = useMemo(
    () => ({ "--calendar-grid-columns": viewMode === "week" ? "7" : "1" }) as CSSProperties,
    [viewMode]
  );

  const renderWeekView = () => (
    <div className={styles.calendarGrid} style={calendarGridStyle}>
      <div className={styles.calendarBody}>
        <div className={styles.calendarBodyScroll} ref={weekScrollRef}>
          <div className={styles.stickyHeaderGroup}>
            <div className={styles.calendarMonthRow}>
              <div className={styles.calendarMonthTitleGroup}>
                <div className={styles.calendarSurfaceNavArrows}>
                  <button
                    type="button"
                    aria-label={t("Previous {range}", { range: rangeNavigationLabel })}
                    onClick={() => handleNavigateRange(-1)}
                  >
                    ‹
                  </button>
                  <button
                    type="button"
                    aria-label={t("Next {range}", { range: rangeNavigationLabel })}
                    onClick={() => handleNavigateRange(1)}
                  >
                    ›
                  </button>
                </div>
                {showTodayControl && (
                  <button
                    type="button"
                    className={styles.calendarSurfaceButton}
                    onClick={handleGoToday}
                    style={{ height: 32, padding: "0 12px", fontSize: "0.55rem" }}
                  >
                    {t("Today")}
                  </button>
                )}
                {showViewSelect && (
                  <div style={{ transform: "scale(0.9)", transformOrigin: "left center" }}>
                    <ViewModeSelect
                      value={viewMode}
                      options={[
                        { value: "week", label: t("Week") },
                        { value: "day", label: t("Day") },
                      ]}
                      onChange={(mode) => updateViewMode(mode)}
                    />
                  </div>
                )}
              </div>
            </div>
            {showHeaderDates && (
              <div className={styles.calendarHeaderRow}>
                <div className={styles.calendarHeaderPlaceholder}>
                  <span className={styles.calendarTimezoneLabel}>{timeZoneLabel}</span>
                </div>
                {weekDays.map((day) => {
                  const isSelectedDay = isSameDay(day, selectedDate);
                  const isToday = nowReference ? isSameDay(day, nowReference) : false;
                  return (
                    <div
                      key={day.toISOString()}
                      className={styles.calendarHeaderCell}
                      data-selected={isSelectedDay ? "true" : "false"}
                      data-today={isToday ? "true" : "false"}
                    >
                      <span>{day.toLocaleDateString(undefined, { weekday: "short" })}</span>
                      <strong>{day.getDate()}</strong>
                    </div>
                  );
                })}
              </div>
            )}
            <div className={styles.calendarAllDayRow}>
              <div className={styles.calendarAllDayLabel}>
                <span>{t("All day")}</span>
              </div>
              {weekDays.map((day) => (
                <div key={day.toISOString()} className={styles.calendarAllDayCell}>
                  {/* All-day events will go here later */}
                </div>
              ))}
            </div>
          </div>
          <div className={styles.calendarTimesColumn}>
            {HOURS_LABEL.map((label, hour) => (
              <span key={label} data-hour={hour}>
                {label}
              </span>
            ))}
            {weekNowIndicator && (
              <>
                <div
                  className={styles.calendarTimelineNowLine}
                  style={{ top: `${weekNowIndicator.offset}px` }}
                  aria-hidden="true"
                />
                <div
                  className={styles.calendarTimelineNowMarker}
                  style={{ top: `${weekNowIndicator.offset}px` }}
                  aria-hidden="true"
                />
              </>
            )}
          </div>
          <div className={styles.calendarWeekColumns} ref={weekColumnsRef}>
            {weekDays.map((day, columnIndex) => {
              const isToday = nowReference ? isSameDay(day, nowReference) : false;
              const columnNowIndicatorOffset =
                weekNowIndicator?.dayIndex === columnIndex ? weekNowIndicator.offset : null;

              const eventsToRender = weekLayouts[columnIndex] || [];

              return (
                <div
                  key={day.toISOString()}
                  className={styles.calendarWeekColumn}
                  data-today={isToday ? "true" : "false"}
                  data-selected={isSameDay(day, selectedDate) ? "true" : "false"}
                >
                  <div
                    className={styles.calendarColumnScroller}
                    onClick={(event) => handleColumnClick(event, day)}
                  >
                    <div className={styles.calendarHourGrid} aria-hidden="true">
                      {HOURS.map((hour) => (
                        <div key={hour} className={styles.calendarHourRow} />
                      ))}
                    </div>
                    {columnNowIndicatorOffset !== null && (
                      <>
                        <div
                          className={styles.nowIndicator}
                          style={{ top: `${columnNowIndicatorOffset}px` }}
                          aria-hidden="true"
                        />
                      </>
                    )}

                    {eventsToRender.map((event) => (
                        <EventCard
                          key={event.id}
                          event={event}
                          onClick={(_e, anchorRect, mouseEvent) => handleEventClick(event, anchorRect, mouseEvent)}
                          draggableProps={
                            isGoogleCalendarEvent(event)
                              ? undefined
                              : viewMode === "week"
                                ? getWeekDraggableProps(event)
                                : undefined
                          }
                          resizeProps={isGoogleCalendarEvent(event) ? undefined : getResizeProps}
                          isDragging={!!activeDrafts?.[event.id]}
                          isSelected={selectedEventIds.has(event.id)}
                          onDelete={handleDeleteEvent}
                        />
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );

  const renderDayView = () => (
    <div className={styles.calendarGrid} style={calendarGridStyle}>
      <div className={styles.calendarBody}>
        <div className={styles.calendarMonthRow}>
          <div className={styles.calendarMonthTitleGroup}>
            <div className={styles.calendarSurfaceNavArrows}>
              <button
                type="button"
                aria-label={t("Previous {range}", { range: rangeNavigationLabel })}
                onClick={() => handleNavigateRange(-1)}
              >
                ‹
              </button>
              <button
                type="button"
                aria-label={t("Next {range}", { range: rangeNavigationLabel })}
                onClick={() => handleNavigateRange(1)}
              >
                ›
              </button>
            </div>
            {showTodayControl && (
              <button
                type="button"
                className={styles.calendarSurfaceButton}
                onClick={handleGoToday}
                style={{ height: 32, padding: "0 12px", fontSize: "0.55rem" }}
              >
                {t("Today")}
              </button>
            )}
            {showViewSelect && (
              <div style={{ transform: "scale(0.9)", transformOrigin: "left center" }}>
                <ViewModeSelect
                  value={viewMode}
                  options={[
                    { value: "week", label: t("Week") },
                    { value: "day", label: t("Day") },
                  ]}
                  onChange={(mode) => updateViewMode(mode)}
                />
              </div>
            )}
          </div>
        </div>
        {showHeaderDates && (
          <div className={styles.calendarHeaderRow}>
            <div className={styles.calendarHeaderPlaceholder}>
              <span className={styles.calendarTimezoneLabel}>+ {timeZoneLabel}</span>
            </div>
            <div
              className={styles.calendarHeaderCell}
              data-selected="true"
              data-today={(nowReference ? isSameDay(selectedDate, nowReference) : false) ? "true" : "false"}
            >
              <span>{selectedDate.toLocaleDateString(undefined, { weekday: "short" })}</span>
              <strong>{selectedDate.getDate()}</strong>
            </div>
          </div>
        )}
        <div
          className={styles.calendarBodyScroll}
          ref={dayColumnRef}
        >
          <div className={styles.calendarTimesColumn}>
            {HOURS_LABEL.map((label, hour) => (
              <span key={label} data-hour={hour}>
                {label}
              </span>
            ))}
            {dayIndicatorOffset !== null && (
              <>
                <div
                  className={styles.calendarTimelineNowLine}
                  style={{ top: `${dayIndicatorOffset}px` }}
                  aria-hidden="true"
                />
              </>
            )}
          </div>
          <div
            className={styles.calendarDayColumn}
            data-selected="true"
            data-today={(nowReference ? isSameDay(selectedDate, nowReference) : false) ? "true" : "false"}
          >
            <div
              className={styles.calendarColumnScroller}
              onClick={(event) => handleColumnClick(event, selectedDate)}
            >
              <div className={styles.calendarHourGrid} aria-hidden="true">
                {HOURS.map((hour) => (
                  <div key={hour} className={styles.calendarHourRow} />
                ))}
              </div>
              {dayIndicatorOffset !== null && (
                <>
                  <div
                    className={styles.nowIndicator}
                    style={{ top: `${dayIndicatorOffset}px` }}
                    aria-hidden="true"
                  />
                </>
              )}

              {/* Events */}
              {dayLayouts.map((event) => (
                <EventCard
                  key={event.id}
                  event={event}
                  onClick={(_e, anchorRect, mouseEvent) => handleEventClick(event, anchorRect, mouseEvent)}
                  draggableProps={
                    isGoogleCalendarEvent(event)
                      ? undefined
                      : viewMode === "day"
                        ? getDraggableProps(event)
                        : undefined
                  }
                  resizeProps={isGoogleCalendarEvent(event) ? undefined : getResizeProps}
                  isDragging={!!activeDrafts?.[event.id]}
                  isSelected={selectedEventIds.has(event.id)}
                  onDelete={handleDeleteEvent}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  const updateSelectedDate = useCallback(
    (compute: (previous: Date) => Date) => {
      const computeNext = (prev: Date) => {
        const next = compute(prev);
        setMonthDate(next);
        return next;
      };

      if (onSelectedDateChange) {
        // If controlled, compute the next date based on current prop (or internal if falling back)
        // and notify parent. Parent is responsible for updating prop.
        const next = computeNext(selectedDate);
        onSelectedDateChange(next);
      } else {
        setInternalSelectedDate((previous) => computeNext(previous));
      }
    },
    [onSelectedDateChange, selectedDate]
  );

  const handleDaySelect = (nextDate: Date) => {
    updateSelectedDate(() => nextDate);
  };

  const handleMonthNavigate = (offset: number) => {
    setMonthDate((previous) => {
      const next = new Date(previous);
      next.setMonth(previous.getMonth() + offset);
      return next;
    });
  };

  const handleNavigateRange = (direction: number) => {
    updateSelectedDate((previous) => {
      const next = new Date(previous);
      const delta = direction * (viewMode === "week" ? 7 : 1);
      next.setDate(previous.getDate() + delta);
      return next;
    });
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartRef.current = {
      x: e.touches[0].clientX,
      y: e.touches[0].clientY,
    };
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStartRef.current) return;

    const touchEnd = {
      x: e.changedTouches[0].clientX,
      y: e.changedTouches[0].clientY,
    };

    const diffX = touchStartRef.current.x - touchEnd.x;
    const diffY = touchStartRef.current.y - touchEnd.y;

    // Determine if swipe is horizontal (X diff > Y diff) and significant enough
    if (Math.abs(diffX) > Math.abs(diffY) && Math.abs(diffX) > 50) {
      if (diffX > 0) {
        // Swiped left -> Next
        handleNavigateRange(1);
      } else {
        // Swiped right -> Previous
        handleNavigateRange(-1);
      }
    }

    touchStartRef.current = null;
  };

  const handleGoToday = () => {
    updateSelectedDate(() => startOfDay(new Date()));
  };

  const calendarStyle: CSSProperties & { [key: string]: string | number | undefined } = {
    "--calendar-hour-height": `${hourHeight}px`,
    "--calendar-timeline-width": `${TIMELINE_WIDTH}px`,
  };

  if (maxHeight !== undefined) {
    const resolvedMaxHeight = typeof maxHeight === "number" ? `${maxHeight}px` : maxHeight;
    calendarStyle["--calendar-max-height"] = resolvedMaxHeight;
  } else {
    calendarStyle["--calendar-max-height"] = "100%";
  }

  const monthLabel = selectedDate.toLocaleDateString(undefined, {
    month: "long",
    year: "numeric",
  });

  const rangeLabel =
    viewMode === "week" ? formatWeekRange(selectedDate) : formatDayLabel(selectedDate);

  const calendarSurfaceClassName = [
    styles.dashboardCalendar,
    showSidebar ? styles.dashboardCalendarWithSidebar : styles.dashboardCalendarStandalone,
    styles.calendarSurface,
    compactSurface ? styles.calendarSurfaceCompact : null,
    surfaceClassName,
    className,
  ]
    .filter(Boolean)
    .join(" ");

  const showViewSelect = showHeaderControls && !viewModeLocked;
  const showTodayControl = showHeaderControls && showTodayButton;
  const showNavigationControls = showHeaderControls;
  const hasHeaderRight =
    showNavigationControls || showTodayControl || showViewSelect;
  const shouldRenderHeader = shouldShowDashboardToggle || showSurfaceHeading || hasHeaderRight;

  const headerProps: DashboardHeaderProps = {
    activeTab: dashboardTab ?? "calendar",
    onSelectTab: (tab) => onSelectDashboardTab?.(tab),
    label: showSurfaceLabel ? t("Calendar") : undefined,
    title: monthLabel,
    rangeLabel: showHeaderDates ? rangeLabel : undefined,
    timezoneLabel: timeZoneLabel,
    onPrevMonth: () => handleMonthNavigate(-1),
    onNextMonth: () => handleMonthNavigate(1),
    onPrevRange: () => handleNavigateRange(-1),
    onNextRange: () => handleNavigateRange(1),
    onGoToday: showTodayControl ? handleGoToday : undefined,
    viewMode,
    onViewModeChange: showViewSelect ? updateViewMode : undefined,
    viewModeOptions: [
      { value: "week", label: t("Week") },
      { value: "day", label: t("Day") },
    ],
    rangeNavigationLabel,
  };

  const handleMainMonthNavigate = (offset: number) => {
    updateSelectedDate((previous) => {
      const next = new Date(previous);
      next.setMonth(previous.getMonth() + offset);
      return next;
    });
  };

  const dashboardToggle = shouldShowDashboardToggle ? (
    <div className={styles.calendarSurfaceHeadingGroup}>
      <div className={styles.calendarSurfaceTabs}>
        <button
          type="button"
          className={styles.calendarSurfaceTab}
          data-active={dashboardTab === "pulse"}
          aria-pressed={dashboardTab === "pulse"}
          onClick={() => onSelectDashboardTab?.("pulse")}
        >
          {t("Pulse")}
        </button>
        <button
          type="button"
          className={styles.calendarSurfaceTab}
          data-active={dashboardTab === "calendar"}
          aria-pressed={dashboardTab === "calendar"}
          onClick={() => onSelectDashboardTab?.("calendar")}
        >
          {t("Calendar")}
        </button>
      </div>
    </div>
  ) : null;

  const headerNode = renderHeader
    ? renderHeader(headerProps)
    : shouldRenderHeader
      ? (
        <header className={styles.calendarSurfaceHeader}>
          <div className={styles.calendarSurfaceHeaderLeft}>
            {dashboardToggle}
            {showSurfaceHeading && (
              <>
                {showSurfaceLabel && (
                  <span className={styles.calendarSurfaceLabel}>{t("Calendar")}</span>
                )}
                <div className={styles.calendarSurfaceTitleRow}>
                  {showNavigationControls && (
                    <div className={styles.calendarSurfaceNavArrows}>
                      <button
                        type="button"
                        aria-label={t("Previous month")}
                        onClick={() => handleMainMonthNavigate(-1)}
                      >
                        ‹
                      </button>
                      <button
                        type="button"
                        aria-label={t("Next month")}
                        onClick={() => handleMainMonthNavigate(1)}
                      >
                        ›
                      </button>
                    </div>
                  )}
                </div>
                {showHeaderDates && (
                  <p className={styles.calendarSurfaceRange}>{rangeLabel}</p>
                )}
              </>
            )}
          </div>
          {hasHeaderRight && (
            <div className={styles.calendarSurfaceHeaderRight}>
              <div className={styles.calendarSurfaceNav}>
                {showNavigationControls && (
                  <>
                    <div className={styles.calendarSurfaceNavArrows} style={{ display: 'none' }}>
                      {/* Hidden here, moved to left */}
                    </div>
                  </>
                )}
                {showTodayControl && (
                  <button
                    type="button"
                    className={styles.calendarSurfaceButton}
                    onClick={handleGoToday}
                  >
                    {t("Today")}
                  </button>
                )}
                {showViewSelect && (
                  <select
                    className={styles.calendarViewSelect}
                    value={viewMode}
                    onChange={handleViewModeChange}
                  >
                    <option value="week">{t("Week")}</option>
                    <option value="day">{t("Day")}</option>
                  </select>
                )}
              </div>
            </div>
          )}
        </header>
      )
      : null;

  const bodyClassName = [
    styles.calendarSurfaceBody,
    embedWithinParentSurface && surfaceClassName ? surfaceClassName : null,
  ]
    .filter(Boolean)
    .join(" ");

  const bodyElement = (
    <div
      className={bodyClassName}
      data-has-sidebar={showSidebar ? "true" : "false"}
      style={embedWithinParentSurface ? calendarStyle : undefined}
    >
      {showSidebar && (
        <div className={styles.calendarSidebarPanel}>
          <CalendarSidebar
            monthDate={monthDate}
            selectedDate={selectedDate}
            onSelectDate={handleDaySelect}
            onNavigate={handleMonthNavigate}
            calendars={calendars}
            onToggleCalendar={handleToggleCalendar}
            showHeader={true}
            showSelectedDateLabel={false}
            className={styles.calendarSidebarIntegrated}
            showMonthNavigation={true}
            showCalendarList={showCalendarList}
            onIntegrationAction={onIntegrationAction}
          />
        </div>
      )}
      <div
        className={styles.calendarBoard}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        {viewMode === "week" ? renderWeekView() : renderDayView()}
      </div>
    </div>
  );

  const eventComposer = (
    <EventComposer
      isOpen={composerOpen}
      referenceDate={selectedDate}
      activeEvent={editingEvent}
      initialRange={composerRange}
      calendars={calendars}
      anchorRect={composerAnchorRect}
      onRequestClose={() => {
        setComposerOpen(false);
        setEditingEvent(null);
        setComposerRange(null);
        setComposerAnchorRect(null);
      }}
      onSubmit={handleComposerSubmit}
      onDelete={handleComposerDelete}
      onStateChange={setComposerDraft}
    />
  );

  if (embedWithinParentSurface) {
    return (
      <>
        {headerNode}
        {bodyElement}
        {eventComposer}
      </>
    );
  }

  return (
    <div
      className={calendarSurfaceClassName}
      style={calendarStyle}
    >
      {headerNode}
      {bodyElement}
      {eventComposer}
    </div>
  );
}

