/* eslint-disable react-hooks/refs */
import { MutableRefObject, useCallback, useRef, useState } from "react";

import { CalendarEvent, EventDraft } from "./types";

const minutesBetween = (anchor: Date, value: Date) =>
    (value.getTime() - anchor.getTime()) / 60000;

const addMinutes = (anchor: Date, minutes: number) =>
    new Date(anchor.getTime() + minutes * 60000);

const snapToInterval = (value: number, interval: number) =>
    (interval > 0 ? Math.round(value / interval) * interval : value);

type UseEventResizeParams = {
    containerRef: MutableRefObject<HTMLElement | null>;
    hourHeight: number;
    snapMinutes?: number;
    onCommit?: (drafts: Record<string, EventDraft>) => void;
};

type ResizeState = {
    pointerId: number;
    initialClientY: number;
    eventId: string;
    originalStart: Date;
    originalEnd: Date;
    edge: "start" | "end";
    activeDraft: EventDraft;
};

export const useEventResize = ({
    containerRef,
    hourHeight,
    snapMinutes = 15,
    onCommit,
}: UseEventResizeParams) => {
    const [resizeState, setResizeState] = useState<ResizeState | null>(null);
    const isResizingRef = useRef(false);
    const latestDraftRef = useRef<EventDraft | null>(null);

    const getResizeProps = useCallback(
        (event: CalendarEvent, edge: "start" | "end") => {
            const handlePointerDown = (pointerEvent: React.PointerEvent<HTMLElement>) => {
                if (pointerEvent.pointerType === "touch" || !containerRef.current) {
                    return;
                }

                pointerEvent.preventDefault();
                pointerEvent.stopPropagation();

                const newResizeState: ResizeState = {
                    pointerId: pointerEvent.pointerId,
                    initialClientY: pointerEvent.clientY,
                    eventId: event.id,
                    originalStart: event.start,
                    originalEnd: event.end,
                    edge,
                    activeDraft: {
                        id: event.id,
                        start: event.start,
                        end: event.end,
                    },
                };

                setResizeState(newResizeState);
                latestDraftRef.current = newResizeState.activeDraft;
                isResizingRef.current = true;

                const target = pointerEvent.currentTarget;
                target.setPointerCapture(newResizeState.pointerId);

                const frameRef = { current: 0 };
                const pendingStateRef = { current: null as ResizeState | null };

                const handleMove = (moveEvent: PointerEvent) => {
                    if (moveEvent.pointerId !== newResizeState.pointerId) return;

                    const minuteHeight = (hourHeight / 60) || 1;
                    const deltaY = moveEvent.clientY - newResizeState.initialClientY;
                    const rawDeltaMinutes = deltaY / minuteHeight;

                    // Round to nearest snap interval
                    const snappedDeltaMinutes = snapToInterval(rawDeltaMinutes, snapMinutes);

                    let newStart = newResizeState.originalStart;
                    let newEnd = newResizeState.originalEnd;

                    if (edge === "start") {
                        newStart = addMinutes(newResizeState.originalStart, snappedDeltaMinutes);
                        // Constraint: End time must be at least snapMinutes after start
                        const minEnd = addMinutes(newStart, snapMinutes);
                        if (minEnd > newEnd) {
                            newStart = addMinutes(newEnd, -snapMinutes);
                        }
                    } else {
                        newEnd = addMinutes(newResizeState.originalEnd, snappedDeltaMinutes);
                        // Constraint: End time must be at least snapMinutes after start
                        const minEnd = addMinutes(newStart, snapMinutes);
                        if (newEnd < minEnd) {
                            newEnd = minEnd;
                        }
                    }

                    const nextDraft: EventDraft = {
                        id: event.id,
                        start: newStart,
                        end: newEnd,
                    };

                    latestDraftRef.current = nextDraft;
                    pendingStateRef.current = { ...newResizeState, activeDraft: nextDraft };

                    if (!frameRef.current) {
                        frameRef.current = requestAnimationFrame(() => {
                            if (pendingStateRef.current) {
                                setResizeState(pendingStateRef.current);
                            }
                            frameRef.current = 0;
                        });
                    }
                };

                const release = () => {
                    target.removeEventListener("pointermove", handleMove);
                    target.removeEventListener("pointerup", handleUp);
                    target.removeEventListener("pointercancel", handleCancel);
                    if (target.hasPointerCapture(newResizeState.pointerId)) {
                        target.releasePointerCapture(newResizeState.pointerId);
                    }
                    if (frameRef.current) {
                        cancelAnimationFrame(frameRef.current);
                        frameRef.current = 0;
                    }
                };

                const handleUp = () => {
                    const finalDraft = latestDraftRef.current;
                    if (finalDraft && onCommit) {
                        onCommit({ [finalDraft.id]: finalDraft });
                    }
                    isResizingRef.current = false;
                    setResizeState(null);
                    latestDraftRef.current = null;
                    release();
                };

                const handleCancel = () => {
                    isResizingRef.current = false;
                    setResizeState(null);
                    latestDraftRef.current = null;
                    release();
                };

                target.addEventListener("pointermove", handleMove);
                target.addEventListener("pointerup", handleUp);
                target.addEventListener("pointercancel", handleCancel);
            };

            return {
                onPointerDown: handlePointerDown,
            };
        },
        [containerRef, hourHeight, onCommit, snapMinutes]
    );

    return {
        activeDraft: resizeState?.activeDraft ?? null,
        getResizeProps,
        isResizing: isResizingRef.current,
    };
};

"use client";

import { useEffect, useState, type MouseEvent } from "react";
import { X, ChevronDown } from "lucide-react";
import styles from "@/app/gray/GrayPageClient.module.css";
import { useUser } from "@/contexts/UserContext";
import { apiService } from "@/lib/api";
import type { HabitItem, HabitUpdates, PlanItem, PlanUpdates } from "./types";
import { useI18n } from "@/contexts/I18nContext";

const toDateTimeLocalValue = (value: string | null | undefined): string => {
  if (!value) {
    return "";
  }
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) {
    return "";
  }
  const offset = parsed.getTimezoneOffset();
  const normalized = new Date(parsed.getTime() - offset * 60000);
  return normalized.toISOString().slice(0, 16);
};

const splitScheduleSlot = (slot: string | null | undefined) => {
  if (!slot) {
    return null;
  }
  const match = slot.match(/^(\d{1,2}:\d{2})-(\d{1,2}:\d{2})$/);
  if (!match) {
    return null;
  }
  return {
    start: match[1],
    end: match[2],
  };
};

type AddPlanHabitModalProps = {
  isOpen: boolean;
  onClose: () => void;
  type: "plan" | "habit";
  onSuccess: () => Promise<void> | void;
  planToEdit?: PlanItem | null;
  onSubmitPlan?: (planId: string | null, updates: PlanUpdates) => Promise<void> | void;
  habitToEdit?: HabitItem | null;
  onSubmitHabit?: (habitId: string | null, updates: HabitUpdates) => Promise<void> | void;
};

export function AddPlanHabitModal({
  isOpen,
  onClose,
  type,
  onSuccess,
  planToEdit,
  onSubmitPlan,
  habitToEdit,
  onSubmitHabit,
}: AddPlanHabitModalProps) {
  const { t } = useI18n();
  const [inputValue, setInputValue] = useState("");
  const [detailsValue, setDetailsValue] = useState("");
  const [planDeadline, setPlanDeadline] = useState("");
  const [planScheduleStart, setPlanScheduleStart] = useState("");
  const [planScheduleEnd, setPlanScheduleEnd] = useState("");
  const [reminderEnabled, setReminderEnabled] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { user } = useUser();
  const [activeType, setActiveType] = useState<"plan" | "habit">(type);

  useEffect(() => {
    setActiveType(type);
  }, [type, isOpen]);
  useEffect(() => {
    if (type !== "plan" || !planToEdit || !isOpen) {
      return;
    }
    setInputValue(planToEdit.label);
    setDetailsValue(planToEdit.details ?? "");
    const slot = splitScheduleSlot(planToEdit.scheduleSlot);
    setPlanScheduleStart(slot?.start ?? "");
    setPlanScheduleEnd(slot?.end ?? "");
    const deadlineValue = toDateTimeLocalValue(planToEdit.deadline ?? "");
    setPlanDeadline(deadlineValue);
    setReminderEnabled(Boolean(deadlineValue));
    setError(null);
  }, [isOpen, planToEdit, type]);

  useEffect(() => {
    if (type !== "habit" || !habitToEdit || !isOpen) {
      return;
    }
    setInputValue(habitToEdit.label);
    setDetailsValue(habitToEdit.details ?? "");
    setError(null);
  }, [habitToEdit, isOpen, type]);

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        onClose();
      }
    };

    if (isOpen) {
      document.addEventListener("keydown", handleKeyDown);
      document.body.style.overflow = "hidden";
    }

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.body.style.overflow = "unset";
    };
  }, [isOpen, onClose]);

  useEffect(() => {
    if (!isOpen) {
      setInputValue("");
      setDetailsValue("");
      setPlanDeadline("");
      setPlanScheduleStart("");
      setPlanScheduleEnd("");
      setReminderEnabled(false);
      setIsSubmitting(false);
      setError(null);
    }
  }, [isOpen]);

  const handleOverlayClick = (event: MouseEvent<HTMLDivElement>) => {
    if (event.target === event.currentTarget) {
      onClose();
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {

    e.preventDefault();

    // console.log('[AddPlanHabitModal] handleSubmit called', { type: activeType, inputValue, user: !!user });



    if (!user) {

      setError(t("You must be signed in to perform this action."));

      return;

    }



    if (!inputValue.trim()) {

      // console.log('[AddPlanHabitModal] Input value is empty, returning');

      return;

    }



    if ((planScheduleStart && !planScheduleEnd) || (!planScheduleStart && planScheduleEnd)) {

      setError(t("Please provide both a start and end time for the schedule."));

      return;

    }



    if (reminderEnabled && !planDeadline) {

      setError(t("Please provide a reminder time when reminder is checked."));

      return;

    }



    setIsSubmitting(true);

    setError(null);

    // console.log('[AddPlanHabitModal] Starting submission...');



    const isEditingPlan = activeType === "plan" && Boolean(planToEdit);

    const isEditingHabit = activeType === "habit" && Boolean(habitToEdit);

    try {

      const trimmed = inputValue.trim();

      const details = detailsValue.trim();

      if (activeType === "plan") {

        const scheduleSlotValue =

          planScheduleStart && planScheduleEnd

            ? `${planScheduleStart}-${planScheduleEnd}`

            : null;

        const deadlineValue = planDeadline ? planDeadline : null;

        const descriptionValue = details.length > 0 ? details : null;

        const payload: PlanUpdates = {

          label: trimmed,

          details: descriptionValue,

          deadline: deadlineValue,

          scheduleSlot: scheduleSlotValue,

        };

        // console.log('[AddPlanHabitModal] Saving plan', { isEditing: isEditingPlan, payload, hasOnSubmitPlan: !!onSubmitPlan });

        if (onSubmitPlan) {

          await onSubmitPlan(planToEdit?.id ?? null, payload);

        } else {

          const result = await apiService.createPlan(user.id, {

            label: trimmed,

            completed: false,

            deadline: deadlineValue,

            scheduleSlot: scheduleSlotValue,

            description: descriptionValue,

          });

          // console.log('[AddPlanHabitModal] Plan created successfully', result);

        }

      } else {

        if (isEditingHabit) {

          const payload: HabitUpdates = {

            label: trimmed,

            details: details.length > 0 ? details : null,

          };

          // console.log('[AddPlanHabitModal] Updating habit', { payload, hasOnSubmitHabit: !!onSubmitHabit });

          if (onSubmitHabit) {

            await onSubmitHabit(habitToEdit?.id ?? null, payload);

          } else if (user && habitToEdit) {

            const habitId = Number(habitToEdit.id);

            await apiService.updateHabit(user.id, habitId, {

              label: payload.label,

              description: payload.details ?? null,

            });

          }

        } else {

          // console.log('[AddPlanHabitModal] Creating new habit');

          const result = await apiService.createHabit(user.id, {

            label: trimmed,

            previous_label: t("No history yet"),

            description: details.length > 0 ? details : null,

          });

          // console.log('[AddPlanHabitModal] Habit created successfully', result);

        }

      }



      setInputValue("");

      setDetailsValue("");

      setPlanDeadline("");

      setPlanScheduleStart("");

      setPlanScheduleEnd("");

      // console.log('[AddPlanHabitModal] Calling onSuccess...');

      await onSuccess();

      // console.log('[AddPlanHabitModal] onSuccess completed, closing modal');

      onClose();

    } catch (err) {

      const typeLabel = activeType === "plan" ? t("Plan") : t("Habit");
      const fallbackError = isEditingPlan || isEditingHabit
        ? t("Failed to update {type}", { type: typeLabel })
        : t("Failed to add {type}", { type: typeLabel });

      console.error(`[AddPlanHabitModal] Failed to ${isEditingPlan || isEditingHabit ? "update" : "add"} ${activeType}:`, err);

      setError(err instanceof Error ? err.message : fallbackError);

    } finally {

      setIsSubmitting(false);

    }

  };

  const handleInputChange = (value: string) => {
    setInputValue(value);
    setError(null);
  };

  const handleDetailsChange = (value: string) => {
    setDetailsValue(value);
  };

  if (!isOpen) {
    return null;
  }

  const isPlan = activeType === "plan";
  const isEditing = Boolean(planToEdit || habitToEdit);
  const title = isPlan ? t("Add Plan") : t("Add Habit");

  return (
    <div
      className={styles.personalizationOverlay}
      onClick={handleOverlayClick}
      role="presentation"
    >
      <div
        className={styles.personalizationPanel}
        role="dialog"
        aria-modal="true"
        aria-labelledby="add-item-title"
        onClick={(event) => event.stopPropagation()}
        style={{ maxWidth: "520px" }}
      >
        <header className={styles.personalizationPanelHeader}>
          <div>
            {!isEditing ? (
              <div className={styles.personalizationHeaderTypeSelect}>
                <span className={styles.personalizationEyebrow} style={{ position: "absolute", top: "-18px", left: "2px" }}>
                  {t("Create new")}
                </span>
                <select
                  value={activeType}
                  onChange={(e) => setActiveType(e.target.value as "plan" | "habit")}
                  className={styles.personalizationHeaderSelect}
                  aria-label={t("Select item type")}
                >
                  <option value="plan">{t("Add Plan")}</option>
                  <option value="habit">{t("Add Habit")}</option>
                </select>
                <ChevronDown className={styles.personalizationHeaderSelectArrow} />
              </div>
            ) : (
              <h2 id="add-item-title">{title}</h2>
            )}
          </div>
          <button
            type="button"
            className={styles.personalizationClose}
            onClick={onClose}
            aria-label={t("Close modal")}
          >
            <X size={18} />
          </button>
        </header>

        <form
          onSubmit={handleSubmit}
          className={styles.personalizationGrid}
          style={{
            marginTop: "12px",
            gridTemplateColumns: "minmax(0, 1fr)",
            alignItems: "stretch",
          }}
        >
          <div className={styles.personalizationColumn}>
            {isPlan ? (
              <>
                <div className={styles.personalizationFieldGroup}>
                  <label htmlFor="plan-description">{t("Plan *")}</label>
                  <textarea
                    id="plan-description"
                    className={styles.personalizationField}
                    value={inputValue}
                    onChange={(event) => handleInputChange(event.target.value)}
                    placeholder={t("What needs to happen?")}
                    disabled={isSubmitting}
                    rows={3}
                    autoFocus
                    required
                  />
                </div>

                <div className={styles.personalizationFieldGroup}>
                  <label htmlFor="plan-details">{t("Details")}</label>
                  <textarea
                    id="plan-details"
                    className={styles.personalizationField}
                    value={detailsValue}
                    onChange={(event) => handleDetailsChange(event.target.value)}
                    placeholder={t("Add notes, links, or context")}
                    disabled={isSubmitting}
                    rows={3}
                  />
                </div>

                <div
                  style={{
                    display: "flex",
                    flexWrap: "wrap",
                    gap: "20px",
                    marginTop: "20px",
                    alignItems: "flex-end",
                  }}
                >
                  <div
                    className={styles.personalizationFieldGroup}
                    style={{ minWidth: "260px", flex: "1 1 260px" }}
                  >
                    <label htmlFor="plan-schedule-start">{t("Schedule window")}</label>
                    <div
                      style={{
                        display: "grid",
                        gridTemplateColumns: "repeat(2, minmax(110px, 1fr))",
                        gap: "14px",
                        marginTop: "12px",
                      }}
                    >
                      <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
                        <span
                          className={styles.personalizationHint}
                          style={{ textTransform: "uppercase", letterSpacing: "0.2em" }}
                        >
                          {t("Start")}
                        </span>
                        <input
                          id="plan-schedule-start"
                          type="time"
                          className={styles.personalizationField}
                          value={planScheduleStart}
                          onChange={(event) => setPlanScheduleStart(event.target.value)}
                          disabled={isSubmitting}
                          step={300}
                        />
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
                        <span
                          className={styles.personalizationHint}
                          style={{ textTransform: "uppercase", letterSpacing: "0.2em" }}
                        >
                          {t("End")}
                        </span>
                        <input
                          id="plan-schedule-end"
                          type="time"
                          className={styles.personalizationField}
                          value={planScheduleEnd}
                          onChange={(event) => setPlanScheduleEnd(event.target.value)}
                          disabled={isSubmitting}
                          step={300}
                        />
                      </div>
                    </div>
                  </div>
                  <div
                    className={styles.personalizationFieldGroup}
                    style={{
                      minWidth: "200px",
                      flex: "1 1 200px",
                      display: "flex",
                      flexDirection: "column",
                      gap: "8px",
                    }}
                  >
                    <div className={styles.reminderCheckboxRow}>
                      <label className={styles.reminderCheckboxLabel}>
                        <input
                          type="checkbox"
                          checked={reminderEnabled}
                          onChange={(event) => {
                            const checked = event.target.checked;
                            setReminderEnabled(checked);
                            if (!checked) {
                              setPlanDeadline("");
                            }
                          }}
                          disabled={isSubmitting}
                          className={styles.reminderCheckboxInput}
                        />
                        {t("Reminder")}
                      </label>
                    </div>
                    <div
                      className={styles.reminderDatePicker}
                      data-hidden={!reminderEnabled}
                    >
                      <input
                        id="plan-reminder"
                        type="datetime-local"
                        className={styles.personalizationField}
                        value={planDeadline}
                        onChange={(event) => setPlanDeadline(event.target.value)}
                        disabled={isSubmitting || !reminderEnabled}
                      />
                    </div>
                  </div>
                </div>

                {error && (
                  <p className={styles.personalizationHint} style={{ color: "#ff6b6b", marginTop: "12px" }}>
                    {error}
                  </p>
                )}
              </>
            ) : (
              <>
                <div className={styles.personalizationFieldGroup}>
                  <label htmlFor="habit-label">{t("Habit *")}</label>
                  <input
                    id="habit-label"
                    type="text"
                    className={styles.personalizationField}
                    value={inputValue}
                    onChange={(event) => handleInputChange(event.target.value)}
                    placeholder={t("Name the habit...")}
                    disabled={isSubmitting}
                    autoFocus
                    required
                  />
                </div>
                <div className={styles.personalizationFieldGroup} style={{ marginTop: "16px" }}>
                  <label htmlFor="habit-details">{t("Details")}</label>
                  <textarea
                    id="habit-details"
                    className={styles.personalizationField}
                    value={detailsValue}
                    onChange={(event) => handleDetailsChange(event.target.value)}
                    placeholder={t("What does success look like?")}
                    disabled={isSubmitting}
                    rows={3}
                  />
                </div>
                {error && (
                  <p className={styles.personalizationHint} style={{ color: "#ff6b6b", marginTop: "12px" }}>
                    {error}
                  </p>
                )}
              </>
            )}

            <div style={{ display: "flex", gap: "12px", marginTop: "28px" }}>
              <button
                type="button"
                className={styles.personalizationLink}
                onClick={onClose}
                disabled={isSubmitting}
                style={{ flex: 1 }}
              >
                {t("Cancel")}
              </button>
              <button
                type="submit"
                className={styles.secondaryAction}
                disabled={!inputValue.trim() || isSubmitting}
                style={{ flex: 1 }}
              >
                {isSubmitting ? t("Saving...") : t("Save")}
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import styles from "@/app/gray/GrayPageClient.module.css";
import Image from "next/image";
import { Paperclip, ArrowUpRight } from "lucide-react";
import {
  type ClipboardEvent as ReactClipboardEvent,
  type FormEvent,
  useCallback,
  useState,
  useEffect,
  useRef,
} from "react";
import TextareaAutosize from "react-textarea-autosize";
import { useI18n } from "@/contexts/I18nContext";

export type GrayChatBarProps = {
  value: string;
  onChange: (value: string) => void;
  onSubmit: (event: FormEvent<HTMLFormElement>) => void;
  placeholder?: string;
  isSubmitDisabled?: boolean;
  isSubmitting?: boolean;
  onAddAttachment?: () => void;
  isReasoningEnabled?: boolean;
  onToggleReasoning?: () => void;
  isReasoningLocked?: boolean;
  isSearchEnabled?: boolean;
  onToggleSearch?: () => void;
  modelSelector?: React.ReactNode;
  onPasteFiles?: (files: File[]) => void;
  attachmentTray?: React.ReactNode;
};

export function GrayChatBar({
  value,
  onChange,
  onSubmit,
  placeholder,
  isSubmitDisabled,
  isSubmitting = false,
  onAddAttachment,
  isReasoningEnabled = false,
  onToggleReasoning,
  isReasoningLocked = false,
  isSearchEnabled = false,
  onToggleSearch,
  modelSelector,
  onPasteFiles,
  attachmentTray,
}: GrayChatBarProps) {
  const { t } = useI18n();
  const resolvedPlaceholder = placeholder ?? t("Ask Gray");
  const computedDisabled =
    typeof isSubmitDisabled === "boolean" ? isSubmitDisabled : value.trim().length === 0;

  // We trigger a re-render/check on mount to ensure mobile detection if needed, 
  // but for TextareaAutosize we mainly just need the component.
  // The original code had isMobile state to prevent enter-submit on mobile.
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      // Use width to determine mobile behavior (Enter = newline vs submit)
      // Pointer: coarse is unreliable on touch-capable laptops
      setIsMobile(window.matchMedia("(max-width: 768px)").matches);
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const handleKeyDown = (event: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (event.key === "Enter" && !event.shiftKey) {
      if (!isMobile) {
        event.preventDefault();
        if (!computedDisabled) {
          // Create a synthetic event to match the expected signature
          const syntheticEvent = {
            preventDefault: () => { },
          } as FormEvent<HTMLFormElement>;
          onSubmit(syntheticEvent);
        }
      }
      // On mobile, let default behavior happen (newline)
    }
  };

  const handlePaste = useCallback(
    (event: ReactClipboardEvent<HTMLTextAreaElement>) => {
      if (!onPasteFiles) {
        return;
      }
      const clipboardFiles = Array.from(event.clipboardData?.files ?? []);
      if (clipboardFiles.length === 0) {
        return;
      }
      onPasteFiles(clipboardFiles);
    },
    [onPasteFiles]
  );

  const handleDrop = useCallback(
    (event: React.DragEvent<HTMLTextAreaElement>) => {
      if (!onPasteFiles) {
        return;
      }
      event.preventDefault();
      const droppedFiles = Array.from(event.dataTransfer.files ?? []);
      if (droppedFiles.length === 0) {
        return;
      }
      onPasteFiles(droppedFiles);
    },
    [onPasteFiles]
  );


  const isStreaming = isSubmitting;
  const actionLabel = isStreaming ? t("Stop response") : t("Send message");
  const isWebSearchInFlight = Boolean(isSubmitting && isSearchEnabled);

  // Track if textarea is expanded beyond single line
  const [isExpanded, setIsExpanded] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement | null>(null);

  // Only expand when there are actual newlines (user pressed Enter)
  // This avoids premature expansion from text wrapping
  const handleHeightChange = useCallback(
    (_height: number, meta: { rowHeight: number }) => {
      // Check for explicit newlines in the content
      const hasExplicitNewlines = value.includes('\n');

      if (hasExplicitNewlines) {
        setIsExpanded(true);
        return;
      }

      // Also check if the textarea has actually grown beyond ~1.5 lines
      // based on its scrollHeight vs the row height
      const textarea = textareaRef.current;
      if (textarea && meta.rowHeight > 0) {
        const visualLines = textarea.scrollHeight / meta.rowHeight;
        setIsExpanded(visualLines > 1.8);
      } else {
        setIsExpanded(false);
      }
    },
    [value]
  );

  return (
    <form className={styles.chatBarRounded} onSubmit={onSubmit} data-expanded={isExpanded} data-has-attachments={attachmentTray ? "true" : "false"}>
      {attachmentTray && (
        <div className={styles.chatAttachmentTrayTop}>
          {attachmentTray}
        </div>
      )}
      {/* Input row: on desktop includes all controls, on mobile just input */}
      <div className={styles.chatBarInputRow}>
        {/* Left group - visible on desktop only */}
        <div className={`${styles.chatBarLeftGroup} ${styles.hideOnMobile}`}>
          {onAddAttachment ? (
            <button
              type="button"
              className={styles.chatIconButton}
              aria-label={t("Upload a document")}
              onClick={onAddAttachment}
            >
              <Paperclip size={18} />
            </button>
          ) : null}
        </div>

        <div className={styles.chatInputWrapper}>
          <TextareaAutosize
            ref={textareaRef}
            value={value}
            onChange={(event) => onChange(event.target.value)}
            onKeyDown={handleKeyDown}
            onPaste={handlePaste}
            onDrop={handleDrop}
            onHeightChange={handleHeightChange}
            placeholder={resolvedPlaceholder}
            className={styles.chatInput}
            aria-label={resolvedPlaceholder}
            rows={1}
            minRows={1}
            maxRows={5}
          />
        </div>

        {/* Right group - visible on desktop only */}
        <div className={`${styles.chatBarRightGroup} ${styles.hideOnMobile}`}>
          {isWebSearchInFlight ? (
            <Image
              src="/grayaiwhitenotspinning.svg"
              alt=""
              aria-hidden="true"
              width={18}
              height={18}
              className={`${styles.chatSearchSpinner} ${styles.uiIconImage}`}
            />
          ) : null}
          <div className={styles.chatModelSelectorDirect}>
            {modelSelector}
          </div>
          <button
            type="submit"
            aria-label={actionLabel}
            title={actionLabel}
            className={styles.chatActionButton}
            disabled={computedDisabled}
          >
            {isStreaming ? (
              <span className={styles.chatStopIcon} aria-hidden="true" />
            ) : (
              <ArrowUpRight size={18} />
            )}
          </button>
        </div>
      </div>

      {/* Bottom row: Controls - visible on mobile only */}
      <div className={styles.chatBarControlsRow}>
        <div className={styles.chatBarLeftGroup}>
          {onAddAttachment ? (
            <button
              type="button"
              className={styles.chatIconButton}
              aria-label={t("Upload a document")}
              onClick={onAddAttachment}
            >
              <Paperclip size={18} />
            </button>
          ) : null}
        </div>
        <div className={styles.chatBarRightGroup}>
          {isWebSearchInFlight ? (
            <Image
              src="/grayaiwhitenotspinning.svg"
              alt=""
              aria-hidden="true"
              width={18}
              height={18}
              className={`${styles.chatSearchSpinner} ${styles.uiIconImage}`}
            />
          ) : null}
          <div className={styles.chatModelSelectorDirect}>
            {modelSelector}
          </div>
          <button
            type="submit"
            aria-label={actionLabel}
            title={actionLabel}
            className={styles.chatActionButton}
            disabled={computedDisabled}
          >
            {isStreaming ? (
              <span className={styles.chatStopIcon} aria-hidden="true" />
            ) : (
              <ArrowUpRight size={18} />
            )}
          </button>
        </div>
      </div>
    </form>
  );
}

