"use client";

import styles from "@/app/gray/GrayPageClient.module.css";
import type { GroundingMetadata } from "@/lib/api";
import { buildGroundingSourceCards, buildGroundingSourceFaviconUrl, buildGroundingSourceInitials } from "./groundingSources";
import { getSanitizedSearchEntryHtml } from "./searchEntrySanitizer";

export type ChatMessageGroundingPanelProps = {
  metadata: GroundingMetadata;
  messageId: string;
  previousUserMessageLowercase: string | null;
  t: (message: string, vars?: Record<string, string | number>) => string;
};

export function ChatMessageGroundingPanel({
  metadata,
  messageId,
  previousUserMessageLowercase,
  t,
}: ChatMessageGroundingPanelProps) {
  const searchQueries =
    metadata?.web_search_queries ?? (metadata as { webSearchQueries?: string[] })?.webSearchQueries ?? [];
  const searchEntryPoint =
    metadata?.search_entry_point ??
    (metadata as { searchEntryPoint?: { rendered_content?: string; renderedContent?: string } })?.searchEntryPoint ??
    null;
  const renderedSearchEntry =
    typeof searchEntryPoint?.rendered_content === "string"
      ? searchEntryPoint?.rendered_content
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      : typeof (searchEntryPoint as any)?.renderedContent === "string"
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        ? (searchEntryPoint as any).renderedContent
        : null;
  const sanitizedSearchEntryHtml = renderedSearchEntry ? getSanitizedSearchEntryHtml(renderedSearchEntry) : null;

  const chunks =
    metadata?.grounding_chunks ??
    (metadata as { groundingChunks?: GroundingMetadata["grounding_chunks"] })?.groundingChunks ??
    [];
  const mapSources = chunks
    .map((chunk) => chunk?.maps)
    .filter((maps): maps is NonNullable<(typeof chunks)[number]["maps"]> => Boolean(maps));

  const widgetToken =
    metadata?.google_maps_widget_context_token ??
    (metadata as { googleMapsWidgetContextToken?: string })?.googleMapsWidgetContextToken ??
    null;
  const hasWidget = Boolean(widgetToken);

  const filteredQueries =
    searchQueries.filter((query) => {
      const trimmed = query.trim();
      if (!trimmed) {
        return false;
      }
      if (previousUserMessageLowercase && trimmed.toLowerCase() === previousUserMessageLowercase) {
        return false;
      }
      return true;
    }) ?? [];

  const sourceCards = buildGroundingSourceCards(metadata, t);

  if (sourceCards.length === 0 && mapSources.length === 0 && filteredQueries.length === 0 && !hasWidget && !sanitizedSearchEntryHtml) {
    return null;
  }

  return (
    <div className={styles.chatGroundingPanel}>
      {sanitizedSearchEntryHtml ? (
        <div className={styles.chatGroundingSearchEntryDeck}>
          <div className={styles.chatGroundingSearchEntry} dangerouslySetInnerHTML={{ __html: sanitizedSearchEntryHtml }} />
        </div>
      ) : null}
      {filteredQueries.length > 0 ? (
        <div className={styles.chatGroundingQueries}>
          {filteredQueries.map((query) => (
            <span key={query} className={styles.chatGroundingQueryChip}>
              {query}
            </span>
          ))}
        </div>
      ) : null}
      {sourceCards.length > 0 ? (
        <div className={styles.chatGroundingSourceDeck}>
          <div className={styles.chatGroundingSourceCards}>
            {sourceCards.map((source) => {
              const initials = buildGroundingSourceInitials(source.siteLabel ?? source.title);
              const faviconUrl = buildGroundingSourceFaviconUrl(source);

              const cardContent = (
                <>
                  <div className={styles.chatGroundingSourceCardAvatar}>
                    {faviconUrl ? (
                      <div style={{ position: "relative", width: "16px", height: "16px" }}>
                        <span
                          style={{
                            position: "absolute",
                            top: 0,
                            left: 0,
                            width: "16px",
                            height: "16px",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            fontSize: "10px",
                          }}
                        >
                          {initials}
                        </span>
                        <img
                          src={faviconUrl}
                          alt=""
                          referrerPolicy="no-referrer"
                          style={{
                            position: "absolute",
                            top: 0,
                            left: 0,
                            width: "16px",
                            height: "16px",
                            objectFit: "contain",
                            backgroundColor: "white",
                            borderRadius: "2px",
                          }}
                          onError={(event) => {
                            event.currentTarget.style.display = "none";
                          }}
                        />
                      </div>
                    ) : (
                      initials
                    )}
                  </div>
                  <div className={styles.chatGroundingSourceCardContent}>
                    <div className={styles.chatGroundingSourceCardTitle}>{source.title ?? t("Referenced source")}</div>
                    {source.siteLabel ? <div className={styles.chatGroundingSourceCardSite}>{source.siteLabel}</div> : null}
                  </div>
                </>
              );

              if (source.href) {
                return (
                  <a
                    key={source.id}
                    href={source.href}
                    target="_blank"
                    rel="noreferrer"
                    className={styles.chatGroundingSourceCard}
                  >
                    {cardContent}
                  </a>
                );
              }

              return (
                <div key={source.id} className={styles.chatGroundingSourceCard} data-clickable="false">
                  {cardContent}
                </div>
              );
            })}
          </div>
        </div>
      ) : null}
      {mapSources.length > 0 ? (
        <div className={styles.chatGroundingSources}>
          {mapSources.map((maps, index) => {
            const label = maps.title ?? maps.placeId ?? t("Maps source");
            const href = maps.uri ?? maps.googleMapsUri ?? undefined;
            return (
              <div key={`${messageId}-maps-source-${index}`} className={styles.chatGroundingSource}>
                {href ? (
                  <a href={href} target="_blank" rel="noreferrer" className={styles.chatGroundingLink}>
                    <span translate="no">Google Maps</span> · {label}
                  </a>
                ) : (
                  <span className={styles.chatGroundingPlain}>
                    <span translate="no">Google Maps</span> · {label}
                  </span>
                )}
              </div>
            );
          })}
        </div>
      ) : null}
      {hasWidget ? (
        <div className={styles.chatGroundingWidget}>
          <span>{t("Widget token:")}</span>
          <code>{widgetToken}</code>
        </div>
      ) : null}
    </div>
  );
}

"use client";

import { memo, useCallback, useRef, useState, type RefObject } from "react";
import ReactMarkdown, { type Components } from "react-markdown";
import rehypeKatex from "rehype-katex";
import styles from "@/app/gray/GrayPageClient.module.css";
import { useI18n } from "@/contexts/I18nContext";
import { REMINDER_CODE_BLOCK_REGEX } from "../constants";
import { stripGrayTitleMarkers } from "../utils";
import type { ChatMessage as ChatSessionMessage } from "../types";
import { extractCurrentToolStatus, parseStructuredAssistantMessage } from "./assistantMessageParsing";
import { estimateTokenCount, formatBackendTimingLabel, formatMessageTimestamp } from "./formatting";
import { ChatMessageAttachments } from "./ChatMessageAttachments";
import { ChatMessageEditor } from "./ChatMessageEditor";
import { ChatMessageFooter } from "./ChatMessageFooter";
import { ChatMessageGroundingPanel } from "./ChatMessageGroundingPanel";
import { GrayStreamingSpinner } from "./GrayStreamingSpinner";
import { MARKDOWN_PLUGINS } from "./markdown/plugins";
import { normalizeAssistantMath } from "./markdown/mathNormalization";
import { ReminderCard } from "./ReminderCard";
import { ThinkingBlock } from "./ThinkingBlock";

export type ChatMessagesListProps = {
  messages: ChatSessionMessage[];
  activeStreamingMessageId: string | null;
  regeneratingMessageId: string | null;
  copiedMessageId: string | null;
  markdownComponents: Components;
  getResponseDurationLabel: (messageIndex: number) => string | null;
  handleCopyMessage: (messageId: string, text: string) => void;
  handleRegenerate: (messageId: string) => void;
  handleRetryUserMessage: (messageId: string) => void;
  handleDeleteMessage: (messageId: string) => void;
  handleCycleAssistantVariant: (messageId: string, direction: "prev" | "next") => void;
  handleEditMessage: (messageId: string, newContent: string) => void;
  shouldShowPendingStreamIndicator: boolean;
  scrollAnchorRef: RefObject<HTMLDivElement | null>;
  reasoningSeconds?: number | null;
  isResponding?: boolean;
  isActivelyThinking?: boolean;
  thinkingStartTime?: number | null;
};

export const ChatMessagesList = memo(
  ({
    messages,
    activeStreamingMessageId,
    regeneratingMessageId,
    copiedMessageId,
    markdownComponents,
    getResponseDurationLabel,
    handleCopyMessage,
    handleRegenerate,
    handleRetryUserMessage,
    handleDeleteMessage,
    handleCycleAssistantVariant,
    handleEditMessage,
    shouldShowPendingStreamIndicator,
    scrollAnchorRef,
    reasoningSeconds,
    isResponding,
    isActivelyThinking,
    thinkingStartTime,
  }: ChatMessagesListProps) => {
    const { t } = useI18n();
    const [editingMessageId, setEditingMessageId] = useState<string | null>(null);
    // Use ref instead of state to avoid re-rendering on every keystroke
    const editContentRef = useRef<string>("");
    const editTextareaRef = useRef<HTMLTextAreaElement | null>(null);
    // Track which message has its action bar expanded (tap to reveal)
    const [expandedMessageId, setExpandedMessageId] = useState<string | null>(null);

    const startEditing = useCallback((messageId: string, currentContent: string) => {
      setEditingMessageId(messageId);
      editContentRef.current = currentContent;
    }, []);

    const cancelEditing = useCallback(() => {
      setEditingMessageId(null);
      editContentRef.current = "";
    }, []);

    const saveEditing = useCallback(
      (messageId: string) => {
        const content = editTextareaRef.current?.value || editContentRef.current;
        if (content.trim()) {
          handleEditMessage(messageId, content);
        }
        setEditingMessageId(null);
        editContentRef.current = "";
      },
      [handleEditMessage]
    );

    // Toggle message action bar visibility on tap/click
    const toggleMessageActions = useCallback((messageId: string) => {
      setExpandedMessageId((prev) => (prev === messageId ? null : messageId));
    }, []);

    return (
      <div className={styles.chatMessages} data-streaming={shouldShowPendingStreamIndicator ? "true" : undefined}>
        {/* eslint-disable-next-line react-hooks/rules-of-hooks -- Refs are intentionally accessed in render for edit mode */}
	        {messages.map((message, messageIndex) => {
	          const isUser = message.role === "user";
	          const isAssistant = !isUser;
	          const rawContent = message.content ?? "";
	          const assistantSections = isAssistant ? parseStructuredAssistantMessage(rawContent) : null;
	          const thinkingText = isAssistant ? assistantSections?.thinking ?? null : null;
	          const aiText = isAssistant ? assistantSections?.ai ?? rawContent : rawContent;
          const assistantTextCandidate = isAssistant ? aiText : rawContent;
          const sanitizedAssistantTextCandidate = stripGrayTitleMarkers(assistantTextCandidate);
          const assistantTextAfterRemovals = isAssistant
            ? sanitizedAssistantTextCandidate.replace(REMINDER_CODE_BLOCK_REGEX, "").trim()
            : sanitizedAssistantTextCandidate;
          const visibleAssistantText = isAssistant ? normalizeAssistantMath(assistantTextAfterRemovals) ?? "" : assistantTextAfterRemovals;
          const normalizedThinkingText = isAssistant ? normalizeAssistantMath(thinkingText) : thinkingText;
          const fullText = isAssistant ? visibleAssistantText : rawContent;
          const hasThinkingContent = typeof normalizedThinkingText === "string" && normalizedThinkingText.trim().length > 0;
	          const isStreamingMessage = isAssistant && message.id === activeStreamingMessageId;
	          const hasTextContent = Boolean(visibleAssistantText.trim());
	          const assistantReminders = isAssistant && Array.isArray(message.reminders) ? message.reminders : [];
	          const showAssistantMarkdown = isAssistant && hasTextContent;
	          const hasVisibleContent = hasThinkingContent || showAssistantMarkdown || assistantReminders.length > 0;
	          const isStreamingAssistantMessage = isAssistant && isStreamingMessage;
	          const isAwaitingStreamContent = isStreamingAssistantMessage && !hasVisibleContent;
	          const showStreamingIndicator = isStreamingAssistantMessage;
          const shouldHideEmptyAssistantMessage = isAssistant && !hasVisibleContent && !isAwaitingStreamContent;
          const messageTimestampIso =
            typeof message.createdAt === "number" && Number.isFinite(message.createdAt)
              ? new Date(message.createdAt).toISOString()
              : undefined;
          const timestampLabel = formatMessageTimestamp(message.createdAt, t);

          if (shouldHideEmptyAssistantMessage) {
            return null;
          }

          if (isUser && !rawContent.trim()) {
            return null;
          }

          const responseDurationLabel = isAssistant ? getResponseDurationLabel(messageIndex) : null;
          const tokenCount = isAssistant ? estimateTokenCount(rawContent) : null;
          const hasTokenEstimate = typeof tokenCount === "number" && Number.isFinite(tokenCount) && tokenCount > 0;
          const metadataTokenLabel = hasTokenEstimate ? t("{count} tokens", { count: tokenCount.toLocaleString() }) : "—";
          const metadataRows: { label: string; value: string }[] = [];
          metadataRows.push({ label: t("Tokens"), value: metadataTokenLabel });
          if (responseDurationLabel) {
            metadataRows.push({ label: t("Duration"), value: responseDurationLabel });
          }
	          const backendTimingLabel = formatBackendTimingLabel(message.backendTimings);
	          if (backendTimingLabel) {
	            metadataRows.push({ label: t("Backend"), value: backendTimingLabel });
	          }
	          const isRegenerating = regeneratingMessageId === message.id;
	          const messageBodyClassName = isUser ? `${styles.chatBubble} ${styles.chatBubbleUser}` : styles.chatAssistantBlock;

          return (
            <div
              key={message.id}
              className={styles.chatMessage}
              data-role={isUser ? "user" : "assistant"}
              data-streaming={isStreamingMessage ? "true" : undefined}
              data-actions-expanded={expandedMessageId === message.id ? "true" : undefined}
              onClick={() => {
                // Only toggle if not editing
                if (!editingMessageId) {
                  toggleMessageActions(message.id);
                }
              }}
            >
              {message.attachments && message.attachments.length > 0 ? (
                <ChatMessageAttachments attachments={message.attachments} t={t} />
              ) : null}
              <div className={messageBodyClassName}>
                {editingMessageId === message.id ? (
                  <ChatMessageEditor
                    defaultValue={editContentRef.current}
                    textareaRef={editTextareaRef}
                    onCancel={cancelEditing}
                    onSave={() => saveEditing(message.id)}
                  />
                ) : (
                  <>
                    {isAwaitingStreamContent && <GrayStreamingSpinner toolLabel={extractCurrentToolStatus(rawContent, t)} />}

                    {assistantReminders.length > 0 ? (
                      <div className={styles.reminderCardList}>
                        {assistantReminders.map((reminder, reminderIndex) => (
                          <ReminderCard
                            key={`${message.id}-reminder-${reminderIndex}-${reminder.data.reminder_id ?? reminder.data.id}`}
                            reminder={reminder}
                          />
                        ))}
                      </div>
                    ) : null}
                    {isAssistant && hasThinkingContent && (
                      <ThinkingBlock
                        content={normalizedThinkingText ?? ""}
                        markdownComponents={markdownComponents}
                        reasoningSeconds={message.reasoningSeconds}
                        isActivelyThinking={isStreamingMessage && isActivelyThinking}
                        thinkingStartTime={isStreamingMessage ? thinkingStartTime : null}
                        isStreamingMessage={isStreamingMessage}
                      />
                    )}
                    {hasTextContent && (
                      <div className={styles.chatMarkdown}>
                        <ReactMarkdown
                          components={markdownComponents}
                          remarkPlugins={MARKDOWN_PLUGINS}
                          rehypePlugins={[[rehypeKatex, { strict: false }]]}
                        >
                          {visibleAssistantText}
                        </ReactMarkdown>
                      </div>
                    )}
                    {isAssistant && message.groundingMetadata ? (
                      <ChatMessageGroundingPanel
                        metadata={message.groundingMetadata}
                        messageId={message.id}
                        previousUserMessageLowercase={(() => {
                          for (let index = messageIndex - 1; index >= 0; index -= 1) {
                            const prior = messages[index];
                            if (prior && prior.role === "user" && typeof prior.content === "string") {
                              return prior.content.trim().toLowerCase();
                            }
                          }
                          return null;
                        })()}
                        t={t}
                      />
                    ) : null}
                  </>
                )}
              </div>
              {!showStreamingIndicator && editingMessageId !== message.id && (
                <ChatMessageFooter
                  message={message}
                  isAssistant={isAssistant}
                  rawContent={rawContent}
                  fullText={fullText}
                  timestampIso={messageTimestampIso}
                  timestampLabel={timestampLabel}
                  metadataRows={metadataRows}
                  copiedMessageId={copiedMessageId}
                  isRegenerating={isRegenerating}
                  isResponding={isResponding}
                  onCopyMessage={(text) => handleCopyMessage(message.id, text)}
                  onRegenerate={() => handleRegenerate(message.id)}
                  onEdit={() => startEditing(message.id, rawContent)}
                  onRetry={() => handleRetryUserMessage(message.id)}
                  onDelete={() => handleDeleteMessage(message.id)}
                  onCycleVariant={(direction) => handleCycleAssistantVariant(message.id, direction)}
                  t={t}
                />
              )}
            </div>
          );
        })}

        {shouldShowPendingStreamIndicator && (
          <div className={styles.chatMessage} data-role="assistant">
            <div className={styles.chatAssistantBlock}>
              <GrayStreamingSpinner
                reasoningSeconds={reasoningSeconds}
                toolLabel={
                  // Check the very last message in the list if it's an assistant message
                  messages.length > 0 && messages[messages.length - 1].role === "assistant"
                    ? extractCurrentToolStatus(messages[messages.length - 1].content, t)
                    : null
                }
              />
            </div>
          </div>
        )}

        <div ref={scrollAnchorRef} />
      </div>
    );
  }
);

ChatMessagesList.displayName = "ChatMessagesList";

"use client";

import { memo, useMemo } from "react";
import styles from "@/app/gray/GrayPageClient.module.css";
import { useI18n } from "@/contexts/I18nContext";

// Greeting messages for mobile welcome screen - time-based and fun options
const MORNING_GREETINGS = [
  "Good morning! Ready to conquer the day?",
  "Rise and shine! What's the plan?",
  "Morning! Coffee kicked in yet?",
  "Good morning! Let's make today count.",
  "Up early? I respect that. How can I help?",
  "Morning! The early bird gets the worm. What's yours?",
];

const AFTERNOON_GREETINGS = [
  "Good afternoon! How's the day going?",
  "Afternoon check-in. What do you need?",
  "Hey there! Surviving the afternoon slump?",
  "Good afternoon! Halfway through - what's next?",
  "Still going strong? What can I do?",
  "Afternoon! Need a productivity boost?",
];

const EVENING_GREETINGS = [
  "Good evening! Winding down or ramping up?",
  "Evening! Still hustling, I see.",
  "Good evening! What brings you here?",
  "Hey! Burning the midnight oil?",
  "Evening vibes. How can I help?",
  "Good evening! Let's finish strong.",
];

const NIGHT_GREETINGS = [
  "Still awake? Me too. What's up?",
  "Night owl mode activated. What do you need?",
  "Can't sleep? Let's be productive then.",
  "Late night thoughts? I'm here.",
  "Hello, fellow insomniac. How can I help?",
  "The quiet hours. What's on your mind?",
];

const GENERAL_GREETINGS = [
  "Hey! What's on your mind?",
  "Ready when you are.",
  "What would you like to explore?",
  "Let's get things done.",
  "Ask me anything.",
  "How can I help you today?",
  "What are we working on?",
  "I'm all ears. Well, algorithms.",
  "Your wish is my command. Almost.",
  "Let's make something happen.",
];

const getRandomGreeting = (): string => {
  const hour = new Date().getHours();
  let pool: string[];

  if (hour >= 5 && hour < 12) {
    pool = [...MORNING_GREETINGS, ...GENERAL_GREETINGS];
  } else if (hour >= 12 && hour < 17) {
    pool = [...AFTERNOON_GREETINGS, ...GENERAL_GREETINGS];
  } else if (hour >= 17 && hour < 22) {
    pool = [...EVENING_GREETINGS, ...GENERAL_GREETINGS];
  } else {
    pool = [...NIGHT_GREETINGS, ...GENERAL_GREETINGS];
  }

  return pool[Math.floor(Math.random() * pool.length)];
};

export const MobileWelcomeScreen = memo(() => {
  const { t } = useI18n();
  const greetingKey = useMemo(() => getRandomGreeting(), []);
  const greeting = t(greetingKey);

  return (
    <div className={styles.mobileWelcomeScreen}>
      <div className={styles.mobileWelcomeContent}>
        <div className={styles.mobileWelcomeLogo}>
          <img src="/grayaiwhitenotspinning.svg" alt="" className={styles.uiIconImage} />
        </div>
        <p className={styles.mobileWelcomeGreeting}>{greeting}</p>
      </div>
    </div>
  );
});
